  1в†’/**
  2в†’ * algorithm-state.ts вЂ” Single source of truth for algorithm state management.
  3в†’ *
  4в†’ * ALL state writes go through this module. No other code writes to algorithm
  5в†’ * state files directly.
  6в†’ *
  7в†’ * Architecture:
  8в†’ *   Per-session files: MEMORY/STATE/algorithms/{sessionId}.json
  9в†’ *   One file per session. Multiple runs tracked via phaseHistory resets.
 10в†’ *
 11в†’ * Writers (1 hook, 1 handler):
 12в†’ *   AlgorithmTracker (PostToolUse: Bash,TaskCreate,TaskUpdate,Task)
 13в†’ *     в†’ phaseTransition(), criteriaAdd(), criteriaUpdate(), agentAdd(), effortLevelUpdate()
 14в†’ *     в†’ Real-time effort level inference: upgrades from 'Standard' based on criteria count
 15в†’ *       (>=12 в†’ Extended, >=20 в†’ Advanced, >=40 в†’ Deep)
 16в†’ *   AlgorithmEnrichment (Stop handler in StopOrchestrator)
 17в†’ *     в†’ algorithmEnd(), sweepStaleActive()
 18в†’ *     в†’ Multi-pattern regex extraction + heuristic fallback for effort level
 19в†’ */
 20в†’
 21в†’import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
 22в†’import { join } from 'path';
 23в†’
 24в†’// в”Ђв”Ђ Types в”Ђв”Ђ
 25в†’
 26в†’export type AlgorithmPhase = 'OBSERVE' | 'THINK' | 'PLAN' | 'BUILD' | 'EXECUTE' | 'VERIFY' | 'LEARN' | 'IDLE' | 'COMPLETE';
 27в†’
 28в†’export interface AlgorithmCriterion {
 29в†’  id: string;
 30в†’  description: string;
 31в†’  type: 'criterion' | 'anti-criterion';
 32в†’  status: 'pending' | 'in_progress' | 'completed' | 'failed';
 33в†’  evidence?: string;
 34в†’  createdInPhase: AlgorithmPhase;
 35в†’  taskId?: string;
 36в†’}
 37в†’
 38в†’export interface PhaseEntry {
 39в†’  phase: AlgorithmPhase;
 40в†’  startedAt: number;
 41в†’  completedAt?: number;
 42в†’  criteriaCount: number;
 43в†’  agentCount: number;
 44в†’  /** True if this phase visit is part of a rework cycle */
 45в†’  isRework?: boolean;
 46в†’  /** Which rework iteration (0 = initial run, 1+ = rework) */
 47в†’  reworkIteration?: number;
 48в†’}
 49в†’
 50в†’/** Archive of a completed algorithm cycle (preserved during rework) */
 51в†’export interface ReworkCycle {
 52в†’  iteration: number;
 53в†’  startedAt: number;
 54в†’  completedAt: number;
 55в†’  fromPhase: AlgorithmPhase;
 56в†’  toPhase: AlgorithmPhase;
 57в†’  criteria: AlgorithmCriterion[];
 58в†’  summary?: string;
 59в†’  effortLevel: string;
 60в†’  phaseHistory: PhaseEntry[];
 61в†’}
 62в†’
 63в†’export interface AlgorithmAgent {
 64в†’  name: string;
 65в†’  agentType: string;
 66в†’  status: 'active' | 'completed' | 'failed' | string;
 67в†’  task?: string;
 68в†’  criteriaIds?: string[];
 69в†’  phase?: AlgorithmPhase | string;
 70в†’}
 71в†’
 72в†’export interface AlgorithmState {
 73в†’  active: boolean;
 74в†’  sessionId: string;
 75в†’  taskDescription: string;
 76в†’  currentPhase: AlgorithmPhase;
 77в†’  phaseStartedAt: number;
 78в†’  algorithmStartedAt: number;
 79в†’  sla: 'Instant' | 'Fast' | 'Standard' | 'Extended' | 'Advanced' | 'Deep' | 'Comprehensive' | 'Loop';
 80в†’  /** Canonical field name вЂ” same value as sla, preferred by UI */
 81в†’  effortLevel?: 'Instant' | 'Fast' | 'Standard' | 'Extended' | 'Advanced' | 'Deep' | 'Comprehensive' | 'Loop';
 82в†’  criteria: AlgorithmCriterion[];
 83в†’  agents: AlgorithmAgent[];
 84в†’  capabilities: string[];
 85в†’  prdPath?: string;
 86в†’  phaseHistory: PhaseEntry[];
 87в†’  qualityGate?: {
 88в†’    count: boolean;
 89в†’    length: boolean;
 90в†’    state: boolean;
 91в†’    testable: boolean;
 92в†’    anti: boolean;
 93в†’    open: boolean;
 94в†’  };
 95в†’  currentAction?: string;
 96в†’  completedAt?: number;
 97в†’  summary?: string;
 98в†’  abandoned?: boolean;
 99в†’  /** Number of times this session re-entered the algorithm after completion */
100в†’  reworkCount?: number;
101в†’  /** True when currently in a rework cycle (vs initial run) */
102в†’  isRework?: boolean;
103в†’  /** Archive of each completed algorithm cycle */
104в†’  reworkHistory?: ReworkCycle[];
105в†’  /** History of session name changes on rework (for dashboard display) */
106в†’  previousNames?: Array<{ name: string; changedAt: string }>;
107в†’  /** Loop mode: true when this state represents a Loop runner session */
108в†’  loopMode?: boolean;
109в†’  /** Loop mode: current iteration number */
110в†’  loopIteration?: number;
111в†’  /** Loop mode: max allowed iterations */
112в†’  loopMaxIterations?: number;
113в†’  /** Loop mode: PRD identifier */
114в†’  loopPrdId?: string;
115в†’  /** Loop mode: absolute path to PRD file */
116в†’  loopPrdPath?: string;
117в†’  /** Loop mode: per-iteration progress history */
118в†’  loopHistory?: Array<{
119в†’    iteration: number;
120в†’    startedAt: number;
121в†’    completedAt: number;
122в†’    criteriaPassing: number;
123в†’    criteriaTotal: number;
124в†’    sdkSessionId?: string;
125в†’  }>;
126в†’  /** Parallel agents: number of concurrent agents configured via -a flag */
127в†’  parallelAgents?: number;
128в†’  /** Execution mode: distinguishes loop/interactive/standard for dashboard display */
129в†’  mode?: 'loop' | 'interactive' | 'standard';
130в†’}
131в†’
132в†’// в”Ђв”Ђ Paths в”Ђв”Ђ
133в†’
134в†’const BASE_DIR = process.env.PAI_DIR || join(process.env.HOME!, '.claude');
135в†’const ALGORITHMS_DIR = join(BASE_DIR, 'MEMORY', 'STATE', 'algorithms');
136в†’const SESSION_NAMES_PATH = join(BASE_DIR, 'MEMORY', 'STATE', 'session-names.json');
137в†’
138в†’function ensureDir(): void {
139в†’  if (!existsSync(ALGORITHMS_DIR)) mkdirSync(ALGORITHMS_DIR, { recursive: true });
140в†’}
141в†’
142в†’// в”Ђв”Ђ Read / Write в”Ђв”Ђ
143в†’
144в†’export function readState(sessionId: string): AlgorithmState | null {
145в†’  try {
146в†’    const file = join(ALGORITHMS_DIR, `${sessionId}.json`);
147в†’    if (!existsSync(file)) return null;
148в†’    const raw = readFileSync(file, 'utf-8').trim();
149в†’    if (!raw || raw === '{}') return null;
150в†’    return JSON.parse(raw) as AlgorithmState;
151в†’  } catch {
152в†’    return null;
153в†’  }
154в†’}
155в†’
156в†’const PLACEHOLDER_RE = /^(Starting\.{0,3}|Algorithm run|[0-9a-f]{8})$/i;
157в†’function isPlaceholderName(name: string): boolean {
158в†’  return PLACEHOLDER_RE.test(name);
159в†’}
160в†’
161в†’export function writeState(state: AlgorithmState): void {
162в†’  ensureDir();
163в†’  // Keep effortLevel in sync with sla вЂ” UI reads effortLevel preferentially
164в†’  state.effortLevel = state.sla;
165в†’  // Re-check session-names.json for name updates (placeholder fix + rework rejuvenation)
166в†’  const latestName = getSessionName(state.sessionId);
167в†’  if (!isPlaceholderName(latestName) && latestName !== state.taskDescription) {
168в†’    state.taskDescription = latestName;
169в†’  }
170в†’  writeFileSync(join(ALGORITHMS_DIR, `${state.sessionId}.json`), JSON.stringify(state, null, 2));
171в†’}
172в†’
173в†’function getSessionName(sessionId: string): string {
174в†’  try {
175в†’    if (existsSync(SESSION_NAMES_PATH)) {
176в†’      const names = JSON.parse(readFileSync(SESSION_NAMES_PATH, 'utf-8'));
177в†’      if (names[sessionId]) return names[sessionId];
178в†’    }
179в†’  } catch {}
180в†’  return 'Algorithm run';
181в†’}
182в†’
183в†’// в”Ђв”Ђ Public API в”Ђв”Ђ
184в†’
185в†’/**
186в†’ * Called when a phase transition curl is detected (e.g., "Entering the Think phase").
187в†’ */
188в†’export function phaseTransition(sessionId: string, phase: AlgorithmPhase): void {
189в†’  const now = Date.now();
190в†’  let state = readState(sessionId);
191в†’
192в†’  if (!state) {
193в†’    // No state yet вЂ” create one (algorithm entry curl may have been missed)
194в†’    state = {
195в†’      active: true,
196в†’      sessionId,
197в†’      taskDescription: getSessionName(sessionId),
198в†’      currentPhase: phase,
199в†’      phaseStartedAt: now,
200в†’      algorithmStartedAt: now,
201в†’      sla: 'Standard',
202в†’      criteria: [],
203в†’      agents: [],
204в†’      capabilities: ['Task Tool'],
205в†’      phaseHistory: [{ phase, startedAt: now, criteriaCount: 0, agentCount: 0 }],
206в†’    };
207в†’    writeState(state);
208в†’    return;
209в†’  }
210в†’
211в†’  // New algorithm run within same session?
212в†’  const isNewRun = phase === 'OBSERVE' &&
213в†’    (state.currentPhase === 'LEARN' || state.currentPhase === 'COMPLETE' || state.currentPhase === 'IDLE');
214в†’
215в†’  if (isNewRun) {
216в†’    // Detect rework: session had previous work (criteria or summary = evidence of completed run)
217в†’    const hasPreviousWork = state.criteria.length > 0 || !!state.summary;
218в†’
219в†’    if (hasPreviousWork) {
220в†’      // Archive current cycle into reworkHistory
221в†’      const cycle: ReworkCycle = {
222в†’        iteration: (state.reworkCount ?? 0),
223в†’        startedAt: state.algorithmStartedAt,
224в†’        completedAt: state.completedAt || now,
225в†’        fromPhase: state.currentPhase,
226в†’        toPhase: phase,
227в†’        criteria: [...state.criteria],
228в†’        summary: state.summary,
229в†’        effortLevel: state.sla,
230в†’        phaseHistory: [...state.phaseHistory],
231в†’      };
232в†’      if (!state.reworkHistory) state.reworkHistory = [];
233в†’      state.reworkHistory.push(cycle);
234в†’      state.reworkCount = (state.reworkCount ?? 0) + 1;
235в†’      state.isRework = true;
236в†’    }
237в†’
238в†’    state.active = true;
239в†’    state.currentPhase = phase;
240в†’    state.phaseStartedAt = now;
241в†’    state.algorithmStartedAt = now;
242в†’    state.criteria = [];
243в†’    state.capabilities = ['Task Tool'];
244в†’    const reworkIter = state.reworkCount ?? 0;
245в†’    state.phaseHistory = [{ phase, startedAt: now, criteriaCount: 0, agentCount: 0, isRework: reworkIter > 0, reworkIteration: reworkIter }];
246в†’    delete state.completedAt;
247в†’    delete state.summary;
248в†’    delete state.qualityGate;
249в†’    writeState(state);
250в†’    return;
251в†’  }
252в†’
253в†’  // Normal phase transition вЂ” close previous, open new
254в†’  if (state.phaseHistory.length > 0) {
255в†’    const last = state.phaseHistory[state.phaseHistory.length - 1];
256в†’    if (!last.completedAt) last.completedAt = now;
257в†’  }
258в†’
259в†’  const reworkIter = state.reworkCount ?? 0;
260в†’  state.phaseHistory.push({
261в†’    phase,
262в†’    startedAt: now,
263в†’    criteriaCount: state.criteria.length,
264в†’    agentCount: state.agents.filter((a: any) => a.status === 'active').length,
265в†’    ...(reworkIter > 0 && { isRework: true, reworkIteration: reworkIter }),
266в†’  });
267в†’
268в†’  state.active = true;
269в†’  state.currentPhase = phase;
270в†’  state.phaseStartedAt = now;
271в†’
272в†’  // LEARN sets completedAt for grace period display but stays active
273в†’  // until the Stop handler calls algorithmEnd()
274в†’  if (phase === 'LEARN') {
275в†’    state.completedAt = now;
276в†’  }
277в†’
278в†’  writeState(state);
279в†’}
280в†’
281в†’/**
282в†’ * Called when TaskCreate produces an ISC criterion.
283в†’ * Also handles session reactivation вЂ” ISC criteria arriving for a completed
284в†’ * session is a definitive signal of a new algorithm run.
285в†’ */
286в†’export function criteriaAdd(sessionId: string, criterion: AlgorithmCriterion): void {
287в†’  let state = readState(sessionId);
288в†’
289в†’  // Create state if none exists вЂ” ISC criteria in a new session should not be dropped
290в†’  if (!state) {
291в†’    const now = Date.now();
292в†’    state = {
293в†’      active: true,
294в†’      sessionId,
295в†’      taskDescription: getSessionName(sessionId),
296в†’      currentPhase: 'OBSERVE' as AlgorithmPhase,
297в†’      phaseStartedAt: now,
298в†’      algorithmStartedAt: now,
299в†’      sla: 'Standard' as AlgorithmState['sla'],
300в†’      criteria: [],
301в†’      agents: [],
302в†’      capabilities: ['Task Tool'],
303в†’      phaseHistory: [{ phase: 'OBSERVE' as AlgorithmPhase, startedAt: now, criteriaCount: 0, agentCount: 0 }],
304в†’    };
305в†’  }
306в†’
307в†’  // Reactivate completed session вЂ” new ISC criteria = new algorithm run
308в†’  if (!state.active) {
309в†’    const now = Date.now();
310в†’    const hasPreviousWork = state.criteria.length > 0 || !!state.summary;
311в†’
312в†’    // Archive previous cycle if it had work (rework detection)
313в†’    if (hasPreviousWork) {
314в†’      const cycle: ReworkCycle = {
315в†’        iteration: (state.reworkCount ?? 0),
316в†’        startedAt: state.algorithmStartedAt,
317в†’        completedAt: state.completedAt || now,
318в†’        fromPhase: state.currentPhase,
319в†’        toPhase: 'OBSERVE',
320в†’        criteria: [...state.criteria],
321в†’        summary: state.summary,
322в†’        effortLevel: state.sla,
323в†’        phaseHistory: [...state.phaseHistory],
324в†’      };
325в†’      if (!state.reworkHistory) state.reworkHistory = [];
326в†’      state.reworkHistory.push(cycle);
327в†’      state.reworkCount = (state.reworkCount ?? 0) + 1;
328в†’      state.isRework = true;
329в†’    }
330в†’
331в†’    const reworkIter = state.reworkCount ?? 0;
332в†’    state = {
333в†’      ...state,
334в†’      active: true,
335в†’      currentPhase: 'OBSERVE' as AlgorithmPhase,
336в†’      phaseStartedAt: now,
337в†’      algorithmStartedAt: now,
338в†’      sla: 'Standard' as AlgorithmState['sla'],
339в†’      criteria: [],
340в†’      capabilities: ['Task Tool'],
341в†’      phaseHistory: [{ phase: 'OBSERVE' as AlgorithmPhase, startedAt: now, criteriaCount: 0, agentCount: 0, isRework: reworkIter > 0, reworkIteration: reworkIter }],
342в†’      agents: [],
343в†’    };
344в†’    delete state.completedAt;
345в†’    delete state.summary;
346в†’    delete state.qualityGate;
347в†’  }
348в†’
349в†’  // Don't add duplicates
350в†’  if (state.criteria.some(c => c.id === criterion.id)) return;
351в†’
352в†’  state.criteria.push(criterion);
353в†’  writeState(state);
354в†’}
355в†’
356в†’/**
357в†’ * Called when TaskUpdate changes a criterion's status.
358в†’ */
359в†’export function criteriaUpdate(sessionId: string, taskId: string, status: AlgorithmCriterion['status']): void {
360в†’  const state = readState(sessionId);
361в†’  if (!state) return;
362в†’
363в†’  const criterion = state.criteria.find(c => c.taskId === taskId);
364в†’  if (!criterion) return;
365в†’
366в†’  criterion.status = status;
367в†’  writeState(state);
368в†’}
369в†’
370в†’/**
371в†’ * Called when the Algorithm's OBSERVE phase selects an effort level.
372в†’ * Detected in real-time by AlgorithmTracker from response text.
373в†’ */
374в†’export function effortLevelUpdate(sessionId: string, level: AlgorithmState['sla']): void {
375в†’  const state = readState(sessionId);
376в†’  if (!state) return;
377в†’
378в†’  state.sla = level;
379в†’  writeState(state);
380в†’}
381в†’
382в†’/**
383в†’ * Called when a Task tool spawns an agent.
384в†’ */
385в†’export function agentAdd(sessionId: string, agent: { name: string; agentType: string; task?: string; criteriaIds?: string[] }): void {
386в†’  const state = readState(sessionId);
387в†’  if (!state) return;
388в†’
389в†’  // Don't add duplicates
390в†’  if (state.agents.some(a => a.name === agent.name)) return;
391в†’
392в†’  const entry: AlgorithmAgent = {
393в†’    name: agent.name,
394в†’    agentType: agent.agentType,
395в†’    status: 'active',
396в†’    task: agent.task,
397в†’    phase: state.currentPhase,
398в†’  };
399в†’  if (agent.criteriaIds) entry.criteriaIds = agent.criteriaIds;
400в†’  state.agents.push(entry);
401в†’  writeState(state);
402в†’}
403в†’
404в†’/**
405в†’ * Called by Stop handler after response is complete.
406в†’ * Enriches state with data extracted from the full transcript.
407в†’ *
408в†’ * Two modes:
409в†’ * - isAlgorithmResponse=true: Enrich with extracted data, mark terminal if LEARN/COMPLETE
410в†’ * - isAlgorithmResponse=false: Deactivate optimistically-activated sessions
411в†’ */
412в†’export function algorithmEnd(
413в†’  sessionId: string,
414в†’  enrichment: {
415в†’    taskDescription?: string;
416в†’    summary?: string;
417в†’    sla?: AlgorithmState['sla'];
418в†’    capabilities?: string[];
419в†’    qualityGate?: AlgorithmState['qualityGate'];
420в†’    criteria?: AlgorithmCriterion[];
421в†’    isAlgorithmResponse: boolean;
422в†’  }
423в†’): void {
424в†’  let state = readState(sessionId);
425в†’
426в†’  // Non-algorithm response: deactivate if it was optimistically activated
427в†’  if (!enrichment.isAlgorithmResponse) {
428в†’    if (state && state.active && state.phaseHistory.length <= 1 && state.criteria.length === 0) {
429в†’      // Session was activated by SessionReactivator but response wasn't algorithm format.
430в†’      // Deactivate to prevent stale active sessions.
431в†’      state.active = false;
432в†’      state.currentPhase = 'COMPLETE';
433в†’      state.completedAt = Date.now();
434в†’      writeState(state);
435в†’    }
436в†’    return;
437в†’  }
438в†’
439в†’  // No state file yet вЂ” create one
440в†’  if (!state) {
441в†’    state = {
442в†’      active: true,
443в†’      sessionId,
444в†’      taskDescription: enrichment.taskDescription || getSessionName(sessionId),
445в†’      currentPhase: 'OBSERVE',
446в†’      phaseStartedAt: Date.now(),
447в†’      algorithmStartedAt: Date.now(),
448в†’      sla: enrichment.sla || 'Standard',
449в†’      criteria: [],
450в†’      agents: [],
451в†’      capabilities: ['Task Tool'],
452в†’      phaseHistory: [],
453в†’    };
454в†’  }
455в†’
456в†’  // Enrich with extracted data
457в†’  if (enrichment.taskDescription) {
458в†’    state.taskDescription = enrichment.taskDescription;
459в†’    state.currentAction = enrichment.taskDescription;
460в†’  }
461в†’  if (enrichment.summary) state.summary = enrichment.summary;
462в†’  if (enrichment.sla) state.sla = enrichment.sla;
463в†’  if (enrichment.capabilities && enrichment.capabilities.length > 0) {
464в†’    state.capabilities = enrichment.capabilities;
465в†’  }
466в†’  if (enrichment.qualityGate) state.qualityGate = enrichment.qualityGate;
467в†’
468в†’  // Merge criteria from transcript (catches any missed by real-time tracker)
469в†’  if (enrichment.criteria && enrichment.criteria.length > 0) {
470в†’    for (const c of enrichment.criteria) {
471в†’      const existing = state.criteria.find(ec => ec.id === c.id);
472в†’      if (existing) {
473в†’        const order = ['pending', 'in_progress', 'completed', 'failed'];
474в†’        if (order.indexOf(c.status) > order.indexOf(existing.status)) {
475в†’          existing.status = c.status;
476в†’          if (c.evidence) existing.evidence = c.evidence;
477в†’        }
478в†’      } else {
479в†’        state.criteria.push(c);
480в†’      }
481в†’    }
482в†’  }
483в†’
484в†’  // Terminal detection вЂ” response is done when phase reached LEARN or COMPLETE.
485в†’  // Summary extraction alone is NOT sufficient вЂ” during compaction, StopOrchestrator
486в†’  // fires with a partial transcript that may contain voice lines from earlier phases.
487в†’  // Only phase-based detection is reliable across compaction boundaries.
488в†’  const isTerminal = state.currentPhase === 'LEARN' || state.currentPhase === 'COMPLETE';
489в†’  if (isTerminal) {
490в†’    state.active = false;
491в†’    state.currentPhase = 'COMPLETE';
492в†’    state.completedAt = state.completedAt || Date.now();
493в†’  }
494в†’
495в†’  writeState(state);
496в†’}
497в†’
498в†’/**
499в†’ * Sweep all algorithm state files and mark stale active sessions as completed.
500в†’ * Called after every response by the StopOrchestrator handler.
501в†’ *
502в†’ * Phase-aware thresholds protect long-running work:
503в†’ * - BUILD/EXECUTE: 60min (art generation, multi-agent swarms, long processes)
504в†’ * - THINK/PLAN/VERIFY: 30min (extended reasoning, complex verification)
505в†’ * - OBSERVE/LEARN/IDLE/other: 15min (should complete quickly)
506в†’ *
507в†’ * File mtime is the staleness signal вЂ” updated by every tool call hook.
508в†’ * Loop items (PRDs) are NOT affected вЂ” they use a separate data store.
509в†’ */
510в†’const STALE_THRESHOLDS_MS: Record<string, number> = {
511в†’  BUILD: 60 * 60 * 1000,    // 60 min
512в†’  EXECUTE: 60 * 60 * 1000,  // 60 min
513в†’  THINK: 30 * 60 * 1000,    // 30 min
514в†’  PLAN: 30 * 60 * 1000,     // 30 min
515в†’  VERIFY: 30 * 60 * 1000,   // 30 min
516в†’};
517в†’const DEFAULT_STALE_MS = 15 * 60 * 1000; // 15 min for OBSERVE, LEARN, IDLE, etc.
518в†’
519в†’const DELETE_AGE_MS = 24 * 60 * 60 * 1000; // 24hr: completed files older than this get deleted
520в†’
521в†’export function sweepStaleActive(currentSessionId: string): void {
522в†’  try {
523в†’    ensureDir();
524в†’    const { readdirSync, statSync, unlinkSync } = require('fs') as typeof import('fs');
525в†’    const now = Date.now();
526в†’    const files = (readdirSync(ALGORITHMS_DIR) as string[]).filter(f => f.endsWith('.json'));
527в†’    const liveSessionIds = new Set<string>();
528в†’
529в†’    for (const file of files) {
530в†’      const sid = file.replace('.json', '');
531в†’      if (sid === currentSessionId) continue; // Skip current session вЂ” handled by algorithmEnd
532в†’
533в†’      try {
534в†’        const filepath = join(ALGORITHMS_DIR, file);
535в†’        const mtime = statSync(filepath).mtimeMs;
536в†’        const age = now - mtime;
537в†’
538в†’        const state = readState(sid);
539в†’        if (!state) continue;
540в†’
541в†’        // Delete completed files older than 24 hours вЂ” they clutter the directory
542в†’        if (!state.active && age > DELETE_AGE_MS) {
543в†’          try {
544в†’            unlinkSync(filepath);
545в†’            process.stderr.write(`[sweep] deleted ${sid} (completed, age ${Math.round(age / 3600000)}h)\n`);
546в†’          } catch {}
547в†’          continue;
548в†’        }
549в†’
550в†’        liveSessionIds.add(sid);
551в†’
552в†’        // Quick skip: anything modified in last 15 min is never stale
553в†’        if (age < DEFAULT_STALE_MS) continue;
554в†’
555в†’        if (!state.active) continue;
556в†’
557в†’        // Phase-aware threshold
558в†’        const threshold = STALE_THRESHOLDS_MS[state.currentPhase] || DEFAULT_STALE_MS;
559в†’        if (age < threshold) continue;
560в†’
561в†’        // Stale active session вЂ” mark completed
562в†’        state.active = false;
563в†’        state.currentPhase = 'COMPLETE';
564в†’        state.completedAt = state.completedAt || now;
565в†’        writeState(state);
566в†’        process.stderr.write(`[sweep] deactivated ${sid} (phase was ${state.currentPhase}, age ${Math.round(age / 60000)}min)\n`);
567в†’      } catch {}
568в†’    }
569в†’
570в†’    // Add current session to live set
571в†’    liveSessionIds.add(currentSessionId);
572в†’
573в†’    // Validate + sync session-names.json вЂ” repair if corrupted, prune orphans
574в†’    try {
575в†’      if (existsSync(SESSION_NAMES_PATH)) {
576в†’        const raw = readFileSync(SESSION_NAMES_PATH, 'utf-8').trim();
577в†’        const names = JSON.parse(raw) as Record<string, string>;
578в†’        const keys = Object.keys(names);
579в†’        let pruned = 0;
580в†’        for (const key of keys) {
581в†’          if (!liveSessionIds.has(key)) {
582в†’            delete names[key];
583в†’            pruned++;
584в†’          }
585в†’        }
586в†’        if (pruned > 0) {
587в†’          writeFileSync(SESSION_NAMES_PATH, JSON.stringify(names, null, 2));
588в†’          process.stderr.write(`[sweep] pruned ${pruned} orphaned entries from session-names.json\n`);
589в†’        }
590в†’      }
591в†’    } catch {
592в†’      process.stderr.write(`[sweep] session-names.json corrupt вЂ” resetting to {}\n`);
593в†’      writeFileSync(SESSION_NAMES_PATH, '{}');
594в†’    }
595в†’
596в†’  } catch {}
597в†’}
598в†’
599в†’/**
600в†’ * Called by POST /api/algorithm/abandon
601в†’ */
602в†’export function algorithmAbandon(sessionId: string): boolean {
603в†’  const state = readState(sessionId);
604в†’  if (!state) return false;
605в†’
606в†’  state.abandoned = true;
607в†’  state.active = false;
608в†’  state.completedAt = state.completedAt || Date.now();
609в†’  writeState(state);
610в†’  return true;
611в†’}
612в†’

  1в†’/**
  2в†’ * change-detection.ts - Utilities for detecting PAI system changes
  3в†’ *
  4в†’ * Parses transcripts for file modification tool_use blocks and categorizes
  5в†’ * changes to determine if background integrity maintenance is needed.
  6в†’ */
  7в†’
  8в†’import { readFileSync, existsSync } from 'fs';
  9в†’import { join, relative, basename } from 'path';
 10в†’import { getPaiDir } from './paths';
 11в†’
 12в†’// ============================================================================
 13в†’// Types
 14в†’// ============================================================================
 15в†’
 16в†’export interface FileChange {
 17в†’  tool: 'Write' | 'Edit' | 'MultiEdit';
 18в†’  path: string;
 19в†’  category: ChangeCategory | null;
 20в†’  isPhilosophical: boolean;
 21в†’  isStructural: boolean;
 22в†’}
 23в†’
 24в†’export type ChangeCategory =
 25в†’  | 'skill'
 26в†’  | 'hook'
 27в†’  | 'workflow'
 28в†’  | 'config'
 29в†’  | 'core-system'
 30в†’  | 'memory-system'
 31в†’  | 'documentation';
 32в†’
 33в†’export type SignificanceLabel = 'trivial' | 'minor' | 'moderate' | 'major' | 'critical';
 34в†’
 35в†’export type ChangeType =
 36в†’  | 'skill_update'
 37в†’  | 'structure_change'
 38в†’  | 'doc_update'
 39в†’  | 'hook_update'
 40в†’  | 'workflow_update'
 41в†’  | 'config_update'
 42в†’  | 'tool_update'
 43в†’  | 'multi_area';
 44в†’
 45в†’export interface IntegrityState {
 46в†’  last_run: string;
 47в†’  last_changes_hash: string;
 48в†’  cooldown_until: string | null;
 49в†’}
 50в†’
 51в†’// ============================================================================
 52в†’// Path Constants
 53в†’// ============================================================================
 54в†’
 55в†’const PAI_DIR = getPaiDir();
 56в†’const STATE_FILE = join(PAI_DIR, 'MEMORY', 'STATE', 'integrity-state.json');
 57в†’
 58в†’// Paths that are excluded from integrity checks
 59в†’const EXCLUDED_PATHS = [
 60в†’  'MEMORY/WORK/',
 61в†’  'MEMORY/LEARNING/',
 62в†’  'MEMORY/STATE/',
 63в†’  'scratch/',
 64в†’  'Plans/',
 65в†’  'projects/',
 66в†’  '.git/',
 67в†’  'node_modules/',
 68в†’  'ShellSnapshots/',
 69в†’];
 70в†’
 71в†’// High-priority paths that always warrant documentation
 72в†’const HIGH_PRIORITY_PATHS = [
 73в†’  'skills/PAI/',
 74в†’  'skills/PAI/USER/',
 75в†’  'PAISYSTEMARCHITECTURE.md',
 76в†’  'SKILLSYSTEM.md',
 77в†’  'MEMORYSYSTEM.md',
 78в†’  'THEHOOKSYSTEM.md',
 79в†’  'THEDELEGATIONSYSTEM.md',
 80в†’  'THENOTIFICATIONSYSTEM.md',
 81в†’  'settings.json',
 82в†’];
 83в†’
 84в†’// Philosophical/architectural patterns in paths
 85в†’const PHILOSOPHICAL_PATTERNS = [
 86в†’  /PAI\/SYSTEM\//i,
 87в†’  /PAI\/USER\//i,
 88в†’  /ARCHITECTURE/i,
 89в†’  /PRINCIPLES/i,
 90в†’  /FOUNDING/i,
 91в†’  /IDENTITY/i,
 92в†’];
 93в†’
 94в†’// Structural change patterns
 95в†’const STRUCTURAL_PATTERNS = [
 96в†’  /\/SKILL\.md$/i,           // Skill definitions
 97в†’  /\/Workflows\//i,          // Workflow routing
 98в†’  /settings\.json$/i,        // Configuration
 99в†’  /frontmatter/i,            // Metadata changes
100в†’];
101в†’
102в†’// ============================================================================
103в†’// Transcript Parsing
104в†’// ============================================================================
105в†’
106в†’/**
107в†’ * Parse tool_use blocks from a transcript that modify files.
108в†’ * Extracts Write, Edit, and MultiEdit operations.
109в†’ */
110в†’export function parseToolUseBlocks(transcriptPath: string): FileChange[] {
111в†’  try {
112в†’    if (!existsSync(transcriptPath)) {
113в†’      console.error('[ChangeDetection] Transcript not found:', transcriptPath);
114в†’      return [];
115в†’    }
116в†’
117в†’    const content = readFileSync(transcriptPath, 'utf-8');
118в†’    const lines = content.trim().split('\n');
119в†’    const changes: FileChange[] = [];
120в†’    const seenPaths = new Set<string>();
121в†’
122в†’    for (const line of lines) {
123в†’      if (!line.trim()) continue;
124в†’
125в†’      try {
126в†’        const entry = JSON.parse(line);
127в†’
128в†’        // Look for assistant messages with tool_use
129в†’        if (entry.type === 'assistant' && entry.message?.content) {
130в†’          const contentArray = Array.isArray(entry.message.content)
131в†’            ? entry.message.content
132в†’            : [];
133в†’
134в†’          for (const block of contentArray) {
135в†’            if (block.type !== 'tool_use') continue;
136в†’
137в†’            const toolName = block.name;
138в†’            const input = block.input || {};
139в†’
140в†’            // Handle Write, Edit, MultiEdit tools
141в†’            if (toolName === 'Write' && input.file_path) {
142в†’              const path = normalizeToRelativePath(input.file_path);
143в†’              if (!seenPaths.has(path)) {
144в†’                seenPaths.add(path);
145в†’                changes.push(createFileChange('Write', path));
146в†’              }
147в†’            } else if (toolName === 'Edit' && input.file_path) {
148в†’              const path = normalizeToRelativePath(input.file_path);
149в†’              if (!seenPaths.has(path)) {
150в†’                seenPaths.add(path);
151в†’                changes.push(createFileChange('Edit', path));
152в†’              }
153в†’            } else if (toolName === 'MultiEdit' && input.edits) {
154в†’              for (const edit of input.edits) {
155в†’                if (edit.file_path) {
156в†’                  const path = normalizeToRelativePath(edit.file_path);
157в†’                  if (!seenPaths.has(path)) {
158в†’                    seenPaths.add(path);
159в†’                    changes.push(createFileChange('Edit', path));
160в†’                  }
161в†’                }
162в†’              }
163в†’            }
164в†’          }
165в†’        }
166в†’      } catch {
167в†’        // Skip invalid JSON lines
168в†’      }
169в†’    }
170в†’
171в†’    return changes;
172в†’  } catch (error) {
173в†’    console.error('[ChangeDetection] Error parsing transcript:', error);
174в†’    return [];
175в†’  }
176в†’}
177в†’
178в†’/**
179в†’ * Normalize an absolute path to relative (to PAI_DIR).
180в†’ */
181в†’function normalizeToRelativePath(absolutePath: string): string {
182в†’  if (absolutePath.startsWith(PAI_DIR)) {
183в†’    return relative(PAI_DIR, absolutePath);
184в†’  }
185в†’  return absolutePath;
186в†’}
187в†’
188в†’/**
189в†’ * Create a FileChange object with categorization.
190в†’ */
191в†’function createFileChange(tool: 'Write' | 'Edit', path: string): FileChange {
192в†’  return {
193в†’    tool,
194в†’    path,
195в†’    category: categorizeChange(path),
196в†’    isPhilosophical: isPhilosophicalPath(path),
197в†’    isStructural: isStructuralPath(path),
198в†’  };
199в†’}
200в†’
201в†’// ============================================================================
202в†’// Change Categorization
203в†’// ============================================================================
204в†’
205в†’/**
206в†’ * Categorize a file path by its location in the PAI system.
207в†’ */
208в†’export function categorizeChange(path: string): ChangeCategory | null {
209в†’  // Check exclusions first
210в†’  for (const excluded of EXCLUDED_PATHS) {
211в†’    if (path.includes(excluded)) {
212в†’      return null;
213в†’    }
214в†’  }
215в†’
216в†’  // Check if path is within PAI directory
217в†’  const absolutePath = path.startsWith('/') ? path : join(PAI_DIR, path);
218в†’  if (!absolutePath.startsWith(PAI_DIR)) {
219в†’    return null;
220в†’  }
221в†’
222в†’  // Categorize by path pattern
223в†’  if (path.includes('skills/')) {
224в†’    // Exclude personal/private skills (prefixed with _ by convention)
225в†’    const skillMatch = path.match(/skills\/(_[^/]+)/);
226в†’    if (skillMatch) return null;
227в†’    if (path.includes('/Workflows/')) return 'workflow';
228в†’    if (path.includes('skills/PAI/')) return 'core-system';
229в†’    return 'skill';
230в†’  }
231в†’
232в†’  if (path.includes('hooks/')) return 'hook';
233в†’  if (path.includes('MEMORY/PAISYSTEMUPDATES/')) return 'documentation';
234в†’  if (path.includes('MEMORY/')) return 'memory-system';
235в†’  if (path.endsWith('settings.json')) return 'config';
236в†’  if (path.endsWith('.md') && !path.includes('WORK/')) return 'documentation';
237в†’
238в†’  return null;
239в†’}
240в†’
241в†’/**
242в†’ * Check if a path represents philosophical/architectural content.
243в†’ */
244в†’function isPhilosophicalPath(path: string): boolean {
245в†’  for (const pattern of PHILOSOPHICAL_PATTERNS) {
246в†’    if (pattern.test(path)) return true;
247в†’  }
248в†’  for (const highPriority of HIGH_PRIORITY_PATHS) {
249в†’    if (path.includes(highPriority)) return true;
250в†’  }
251в†’  return false;
252в†’}
253в†’
254в†’/**
255в†’ * Check if a path represents structural content (SKILL.md, workflows, config).
256в†’ */
257в†’function isStructuralPath(path: string): boolean {
258в†’  for (const pattern of STRUCTURAL_PATTERNS) {
259в†’    if (pattern.test(path)) return true;
260в†’  }
261в†’  return false;
262в†’}
263в†’
264в†’// ============================================================================
265в†’// Significance Detection
266в†’// ============================================================================
267в†’
268в†’/**
269в†’ * Determine if changes are significant enough to warrant background integrity check.
270в†’ */
271в†’export function isSignificantChange(changes: FileChange[]): boolean {
272в†’  // Filter to only PAI system changes
273в†’  const systemChanges = changes.filter(c => c.category !== null);
274в†’
275в†’  if (systemChanges.length === 0) return false;
276в†’
277в†’  // Always significant if philosophical or structural changes
278в†’  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
279в†’    return true;
280в†’  }
281в†’
282в†’  // Significant if multiple files in same domain
283в†’  const categories = new Set(systemChanges.map(c => c.category));
284в†’  if (categories.size >= 1 && systemChanges.length >= 2) {
285в†’    return true;
286в†’  }
287в†’
288в†’  // Significant if any skill, hook, or core-system change
289в†’  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'core-system', 'workflow'];
290в†’  if (systemChanges.some(c => importantCategories.includes(c.category!))) {
291в†’    return true;
292в†’  }
293в†’
294в†’  return false;
295в†’}
296в†’
297в†’/**
298в†’ * Check if changes warrant documentation.
299в†’ * UPDATED: Lower thresholds for more granular, frequent documentation.
300в†’ * Philosophy: File system is cheap, more signal is valuable.
301в†’ */
302в†’export function shouldDocumentChanges(changes: FileChange[]): boolean {
303в†’  const systemChanges = changes.filter(c => c.category !== null);
304в†’
305в†’  // No changes to document
306в†’  if (systemChanges.length === 0) return false;
307в†’
308в†’  // Always document philosophical or structural changes
309в†’  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
310в†’    return true;
311в†’  }
312в†’
313в†’  // Document ANY skill, hook, workflow, core-system, or config change
314в†’  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'workflow', 'core-system', 'config'];
315в†’  if (systemChanges.some(c => c.category && importantCategories.includes(c.category))) {
316в†’    return true;
317в†’  }
318в†’
319в†’  // Document if 2+ files changed (lowered from 3+)
320в†’  if (systemChanges.length >= 2) {
321в†’    return true;
322в†’  }
323в†’
324в†’  // Document new file creation in system areas
325в†’  const newFiles = systemChanges.filter(c => c.tool === 'Write');
326в†’  if (newFiles.length > 0) return true;
327в†’
328в†’  // Document any tool file changes (.ts in Tools/)
329в†’  if (systemChanges.some(c => c.path.includes('/Tools/') && c.path.endsWith('.ts'))) {
330в†’    return true;
331в†’  }
332в†’
333в†’  return false;
334в†’}
335в†’
336в†’// ============================================================================
337в†’// Throttling
338в†’// ============================================================================
339в†’
340в†’// Reduced from 5 to 2 minutes for more frequent documentation updates
341в†’const COOLDOWN_MINUTES = 2;
342в†’
343в†’/**
344в†’ * Read the current integrity state.
345в†’ */
346в†’export function readIntegrityState(): IntegrityState | null {
347в†’  try {
348в†’    if (!existsSync(STATE_FILE)) return null;
349в†’    const content = readFileSync(STATE_FILE, 'utf-8');
350в†’    return JSON.parse(content);
351в†’  } catch {
352в†’    return null;
353в†’  }
354в†’}
355в†’
356в†’/**
357в†’ * Check if we're within the cooldown period.
358в†’ */
359в†’export function isInCooldown(): boolean {
360в†’  const state = readIntegrityState();
361в†’  if (!state?.cooldown_until) return false;
362в†’
363в†’  const cooldownUntil = new Date(state.cooldown_until);
364в†’  return new Date() < cooldownUntil;
365в†’}
366в†’
367в†’/**
368в†’ * Generate a hash of changes for deduplication.
369в†’ */
370в†’export function hashChanges(changes: FileChange[]): string {
371в†’  const sorted = changes
372в†’    .map(c => `${c.tool}:${c.path}`)
373в†’    .sort()
374в†’    .join('|');
375в†’
376в†’  // Simple hash
377в†’  let hash = 0;
378в†’  for (let i = 0; i < sorted.length; i++) {
379в†’    const char = sorted.charCodeAt(i);
380в†’    hash = ((hash << 5) - hash) + char;
381в†’    hash = hash & hash;
382в†’  }
383в†’  return hash.toString(16);
384в†’}
385в†’
386в†’/**
387в†’ * Check if changes are duplicates of the last run.
388в†’ */
389в†’export function isDuplicateRun(changes: FileChange[]): boolean {
390в†’  const state = readIntegrityState();
391в†’  if (!state?.last_changes_hash) return false;
392в†’
393в†’  const currentHash = hashChanges(changes);
394в†’  return currentHash === state.last_changes_hash;
395в†’}
396в†’
397в†’/**
398в†’ * Get the cooldown end time.
399в†’ */
400в†’export function getCooldownEndTime(): string {
401в†’  const now = new Date();
402в†’  now.setMinutes(now.getMinutes() + COOLDOWN_MINUTES);
403в†’  return now.toISOString();
404в†’}
405в†’
406в†’// ============================================================================
407в†’// Significance and Change Type Determination
408в†’// ============================================================================
409в†’
410в†’/**
411в†’ * Determine the significance label based on change characteristics.
412в†’ */
413в†’export function determineSignificance(changes: FileChange[]): SignificanceLabel {
414в†’  const count = changes.length;
415в†’  const hasStructural = changes.some(c => c.isStructural);
416в†’  const hasPhilosophical = changes.some(c => c.isPhilosophical);
417в†’  const hasNewFiles = changes.some(c => c.tool === 'Write');
418в†’
419в†’  const categories = new Set(changes.map(c => c.category).filter(Boolean));
420в†’  const hasCoreSystem = changes.some(c => c.category === 'core-system');
421в†’  const hasHooks = changes.some(c => c.category === 'hook');
422в†’  const hasSkills = changes.some(c => c.category === 'skill');
423в†’
424в†’  // Critical: breaking changes, major restructuring
425в†’  if (hasStructural && hasPhilosophical && count >= 5) {
426в†’    return 'critical';
427в†’  }
428в†’
429в†’  // Major: new skills/workflows, architectural decisions
430в†’  if (hasNewFiles && (hasStructural || hasPhilosophical)) {
431в†’    return 'major';
432в†’  }
433в†’  if (hasCoreSystem || (categories.size >= 3)) {
434в†’    return 'major';
435в†’  }
436в†’  if (hasHooks && count >= 3) {
437в†’    return 'major';
438в†’  }
439в†’
440в†’  // Moderate: multi-file updates, small features
441в†’  if (count >= 3 || categories.size >= 2) {
442в†’    return 'moderate';
443в†’  }
444в†’  if (hasSkills && count >= 2) {
445в†’    return 'moderate';
446в†’  }
447в†’
448в†’  // Minor: single file doc updates
449в†’  if (count === 1 && !hasStructural && !hasPhilosophical) {
450в†’    return 'minor';
451в†’  }
452в†’
453в†’  // Trivial: only if very small doc changes
454в†’  if (count === 1 && changes[0].category === 'documentation') {
455в†’    return 'trivial';
456в†’  }
457в†’
458в†’  return 'minor';
459в†’}
460в†’
461в†’/**
462в†’ * Determine the change type based on affected files.
463в†’ */
464в†’export function inferChangeType(changes: FileChange[]): ChangeType {
465в†’  const categories = changes.map(c => c.category).filter(Boolean);
466в†’  const uniqueCategories = new Set(categories);
467в†’
468в†’  // Multi-area if touching 3+ categories
469в†’  if (uniqueCategories.size >= 3) {
470в†’    return 'multi_area';
471в†’  }
472в†’
473в†’  // Single category cases
474в†’  if (uniqueCategories.size === 1) {
475в†’    const cat = [...uniqueCategories][0];
476в†’    switch (cat) {
477в†’      case 'skill': return changes.some(c => c.isStructural) ? 'structure_change' : 'skill_update';
478в†’      case 'hook': return 'hook_update';
479в†’      case 'workflow': return 'workflow_update';
480в†’      case 'config': return 'config_update';
481в†’      case 'core-system': return 'structure_change';
482в†’      case 'documentation': return 'doc_update';
483в†’      default: return 'skill_update';
484в†’    }
485в†’  }
486в†’
487в†’  // Two categories - pick the more significant one
488в†’  if (uniqueCategories.has('hook')) return 'hook_update';
489в†’  if (uniqueCategories.has('skill')) return 'skill_update';
490в†’  if (uniqueCategories.has('workflow')) return 'workflow_update';
491в†’  if (uniqueCategories.has('config')) return 'config_update';
492в†’
493в†’  return 'multi_area';
494в†’}
495в†’
496в†’/**
497в†’ * Generate a descriptive 4-8 word title based on the changes.
498в†’ */
499в†’export function generateDescriptiveTitle(changes: FileChange[]): string {
500в†’  const paths = changes.map(c => c.path);
501в†’
502в†’  // Extract skill names
503в†’  const skillNames = new Set<string>();
504в†’  for (const p of paths) {
505в†’    const match = p.match(/skills\/([^/]+)\//);
506в†’    if (match && match[1] !== 'PAI') skillNames.add(match[1]);
507в†’  }
508в†’
509в†’  // Detect file types
510в†’  const hasSkillMd = paths.some(p => p.endsWith('SKILL.md'));
511в†’  const hasWorkflows = paths.some(p => p.includes('/Workflows/'));
512в†’  const hasTools = paths.some(p => p.includes('/Tools/') && p.endsWith('.ts'));
513в†’  const hasHooks = paths.some(p => p.includes('hooks/'));
514в†’  const hasConfig = paths.some(p => p.endsWith('settings.json'));
515в†’  const hasCoreSystem = paths.some(p => p.includes('skills/PAI/'));
516в†’  const hasCoreUser = paths.some(p => p.includes('PAI/USER/'));
517в†’
518в†’  let title = '';
519в†’
520в†’  // Single skill update
521в†’  if (skillNames.size === 1) {
522в†’    const skill = [...skillNames][0];
523в†’    if (hasSkillMd) {
524в†’      title = `${skill} Skill Definition Update`;
525в†’    } else if (hasWorkflows) {
526в†’      const workflowNames = paths
527в†’        .filter(p => p.includes('/Workflows/'))
528в†’        .map(p => basename(p, '.md'));
529в†’      if (workflowNames.length === 1) {
530в†’        title = `${skill} ${workflowNames[0]} Workflow Update`;
531в†’      } else {
532в†’        title = `${skill} Workflows Updated`;
533в†’      }
534в†’    } else if (hasTools) {
535в†’      const toolNames = paths
536в†’        .filter(p => p.includes('/Tools/'))
537в†’        .map(p => basename(p, '.ts'));
538в†’      if (toolNames.length === 1) {
539в†’        title = `${skill} ${toolNames[0]} Tool Update`;
540в†’      } else {
541в†’        title = `${skill} Tools Updated`;
542в†’      }
543в†’    } else {
544в†’      title = `${skill} Skill Files Updated`;
545в†’    }
546в†’  }
547в†’  // Multiple skills
548в†’  else if (skillNames.size > 1 && skillNames.size <= 3) {
549в†’    const skills = [...skillNames].slice(0, 3).join(' and ');
550в†’    title = `${skills} Skills Updated`;
551в†’  }
552в†’  // Hook changes
553в†’  else if (hasHooks) {
554в†’    const hookNames = paths
555в†’      .filter(p => p.includes('hooks/'))
556в†’      .map(p => basename(p, '.ts').replace('.hook', ''));
557в†’    if (hookNames.length === 1) {
558в†’      title = `${hookNames[0]} Hook Updated`;
559в†’    } else if (hookNames.length <= 3) {
560в†’      title = `${hookNames.slice(0, 3).join(', ')} Hooks Updated`;
561в†’    } else {
562в†’      title = `Hook System Updates`;
563в†’    }
564в†’  }
565в†’  // Config changes
566в†’  else if (hasConfig) {
567в†’    title = 'System Configuration Updated';
568в†’  }
569в†’  // Core system changes
570в†’  else if (hasCoreSystem) {
571в†’    const docNames = paths
572в†’      .filter(p => p.includes('skills/PAI/'))
573в†’      .map(p => basename(p, '.md'));
574в†’    if (docNames.length === 1) {
575в†’      title = `${docNames[0]} Documentation Updated`;
576в†’    } else {
577в†’      title = 'PAI System Documentation Updated';
578в†’    }
579в†’  }
580в†’  // Core user changes
581в†’  else if (hasCoreUser) {
582в†’    const docNames = paths
583в†’      .filter(p => p.includes('PAI/USER/'))
584в†’      .map(p => basename(p, '.md'));
585в†’    if (docNames.length === 1) {
586в†’      title = `${docNames[0]} User Config Updated`;
587в†’    } else {
588в†’      title = 'User Configuration Updated';
589в†’    }
590в†’  }
591в†’  // Fallback
592в†’  else {
593в†’    const categories = new Set(changes.map(c => c.category).filter(Boolean));
594в†’    if (categories.size === 1) {
595в†’      const cat = [...categories][0];
596в†’      title = `${capitalize(cat || 'System')} Updates Applied`;
597в†’    } else {
598в†’      title = 'Multi-Area System Updates Applied';
599в†’    }
600в†’  }
601в†’
602в†’  // Ensure 4-8 words
603в†’  const words = title.split(/\s+/);
604в†’  if (words.length < 4) {
605в†’    title = `PAI ${title}`;
606в†’  } else if (words.length > 8) {
607в†’    title = words.slice(0, 8).join(' ');
608в†’  }
609в†’
610в†’  return title;
611в†’}
612в†’
613в†’function capitalize(s: string): string {
614в†’  return s.charAt(0).toUpperCase() + s.slice(1);
615в†’}
616в†’

  1в†’/**
  2в†’ * Central Identity Loader
  3в†’ * Single source of truth for DA (Digital Assistant) and Principal identity
  4в†’ *
  5в†’ * Reads from settings.json - the programmatic way, not markdown parsing.
  6в†’ * All hooks and tools should import from here.
  7в†’ */
  8в†’
  9в†’import { readFileSync, existsSync } from 'fs';
 10в†’import { join } from 'path';
 11в†’
 12в†’const HOME = process.env.HOME!;
 13в†’const SETTINGS_PATH = join(HOME, '.claude/settings.json');
 14в†’
 15в†’// Default identity (fallback if settings.json doesn't have identity section)
 16в†’const DEFAULT_IDENTITY = {
 17в†’  name: 'PAI',
 18в†’  fullName: 'Personal AI',
 19в†’  displayName: 'PAI',
 20в†’  mainDAVoiceID: '',
 21в†’  color: '#3B82F6',
 22в†’};
 23в†’
 24в†’const DEFAULT_PRINCIPAL = {
 25в†’  name: 'User',
 26в†’  pronunciation: '',
 27в†’  timezone: 'UTC',
 28в†’};
 29в†’
 30в†’export interface VoiceProsody {
 31в†’  stability: number;
 32в†’  similarity_boost: number;
 33в†’  style: number;
 34в†’  speed: number;
 35в†’  use_speaker_boost: boolean;
 36в†’}
 37в†’
 38в†’export interface VoicePersonality {
 39в†’  baseVoice: string;
 40в†’  enthusiasm: number;
 41в†’  energy: number;
 42в†’  expressiveness: number;
 43в†’  resilience: number;
 44в†’  composure: number;
 45в†’  optimism: number;
 46в†’  warmth: number;
 47в†’  formality: number;
 48в†’  directness: number;
 49в†’  precision: number;
 50в†’  curiosity: number;
 51в†’  playfulness: number;
 52в†’}
 53в†’
 54в†’export interface Identity {
 55в†’  name: string;
 56в†’  fullName: string;
 57в†’  displayName: string;
 58в†’  mainDAVoiceID: string;
 59в†’  color: string;
 60в†’  voice?: VoiceProsody;
 61в†’  personality?: VoicePersonality;
 62в†’}
 63в†’
 64в†’export interface Principal {
 65в†’  name: string;
 66в†’  pronunciation: string;
 67в†’  timezone: string;
 68в†’}
 69в†’
 70в†’export interface Settings {
 71в†’  daidentity?: Partial<Identity>;
 72в†’  principal?: Partial<Principal>;
 73в†’  env?: Record<string, string>;
 74в†’  [key: string]: unknown;
 75в†’}
 76в†’
 77в†’let cachedSettings: Settings | null = null;
 78в†’
 79в†’/**
 80в†’ * Load settings.json (cached)
 81в†’ */
 82в†’function loadSettings(): Settings {
 83в†’  if (cachedSettings) return cachedSettings;
 84в†’
 85в†’  try {
 86в†’    if (!existsSync(SETTINGS_PATH)) {
 87в†’      cachedSettings = {};
 88в†’      return cachedSettings;
 89в†’    }
 90в†’
 91в†’    const content = readFileSync(SETTINGS_PATH, 'utf-8');
 92в†’    cachedSettings = JSON.parse(content);
 93в†’    return cachedSettings!;
 94в†’  } catch {
 95в†’    cachedSettings = {};
 96в†’    return cachedSettings;
 97в†’  }
 98в†’}
 99в†’
100в†’/**
101в†’ * Get DA (Digital Assistant) identity from settings.json
102в†’ */
103в†’export function getIdentity(): Identity {
104в†’  const settings = loadSettings();
105в†’
106в†’  // Prefer settings.daidentity, fall back to env.DA for backward compat
107в†’  const daidentity = settings.daidentity || {};
108в†’  const envDA = settings.env?.DA;
109в†’
110в†’  // Support both old (daidentity.voice) and new (daidentity.voices.main) structures
111в†’  const voices = (daidentity as any).voices || {};
112в†’  const voiceConfig = voices.main || (daidentity as any).voice;
113в†’
114в†’  return {
115в†’    name: daidentity.name || envDA || DEFAULT_IDENTITY.name,
116в†’    fullName: daidentity.fullName || daidentity.name || envDA || DEFAULT_IDENTITY.fullName,
117в†’    displayName: daidentity.displayName || daidentity.name || envDA || DEFAULT_IDENTITY.displayName,
118в†’    mainDAVoiceID: voiceConfig?.voiceId || (daidentity as any).voiceId || daidentity.mainDAVoiceID || DEFAULT_IDENTITY.mainDAVoiceID,
119в†’    color: daidentity.color || DEFAULT_IDENTITY.color,
120в†’    voice: voiceConfig as VoiceProsody | undefined,
121в†’    personality: (daidentity as any).personality as VoicePersonality | undefined,
122в†’  };
123в†’}
124в†’
125в†’/**
126в†’ * Get Principal (human owner) identity from settings.json
127в†’ */
128в†’export function getPrincipal(): Principal {
129в†’  const settings = loadSettings();
130в†’
131в†’  // Prefer settings.principal, fall back to env.PRINCIPAL for backward compat
132в†’  const principal = settings.principal || {};
133в†’  const envPrincipal = settings.env?.PRINCIPAL;
134в†’
135в†’  return {
136в†’    name: principal.name || envPrincipal || DEFAULT_PRINCIPAL.name,
137в†’    pronunciation: principal.pronunciation || DEFAULT_PRINCIPAL.pronunciation,
138в†’    timezone: principal.timezone || DEFAULT_PRINCIPAL.timezone,
139в†’  };
140в†’}
141в†’
142в†’/**
143в†’ * Clear cache (useful for testing or when settings.json changes)
144в†’ */
145в†’export function clearCache(): void {
146в†’  cachedSettings = null;
147в†’}
148в†’
149в†’/**
150в†’ * Get just the DA name (convenience function)
151в†’ */
152в†’export function getDAName(): string {
153в†’  return getIdentity().name;
154в†’}
155в†’
156в†’/**
157в†’ * Get just the Principal name (convenience function)
158в†’ */
159в†’export function getPrincipalName(): string {
160в†’  return getPrincipal().name;
161в†’}
162в†’
163в†’/**
164в†’ * Get just the voice ID (convenience function)
165в†’ */
166в†’export function getVoiceId(): string {
167в†’  return getIdentity().mainDAVoiceID;
168в†’}
169в†’
170в†’/**
171в†’ * Get the full settings object (for advanced use)
172в†’ */
173в†’export function getSettings(): Settings {
174в†’  return loadSettings();
175в†’}
176в†’
177в†’/**
178в†’ * Get the default identity (for documentation/testing)
179в†’ */
180в†’export function getDefaultIdentity(): Identity {
181в†’  return { ...DEFAULT_IDENTITY };
182в†’}
183в†’
184в†’/**
185в†’ * Get the default principal (for documentation/testing)
186в†’ */
187в†’export function getDefaultPrincipal(): Principal {
188в†’  return { ...DEFAULT_PRINCIPAL };
189в†’}
190в†’
191в†’/**
192в†’ * Get voice prosody settings (convenience function) - legacy ElevenLabs
193в†’ */
194в†’export function getVoiceProsody(): VoiceProsody | undefined {
195в†’  return getIdentity().voice;
196в†’}
197в†’
198в†’/**
199в†’ * Get voice personality settings (convenience function) - Qwen3-TTS
200в†’ */
201в†’export function getVoicePersonality(): VoicePersonality | undefined {
202в†’  return getIdentity().personality;
203в†’}
