  1в†’#!/usr/bin/env bun
  2в†’/**
  3в†’ * Metadata Extraction Library for UOCS Enhancement
  4в†’ *
  5в†’ * Extracts agent instance IDs, parent-child relationships, and session info
  6в†’ * from Task tool calls and other tool inputs.
  7в†’ *
  8в†’ * Design Philosophy: Optional extraction with graceful fallbacks
  9в†’ * - If instance IDs are present in descriptions/prompts, extract them
 10в†’ * - If not present, fall back to agent type only
 11в†’ * - Never fail - always return usable metadata
 12в†’ */
 13в†’
 14в†’export interface AgentInstanceMetadata {
 15в†’  agent_instance_id?: string;      // "perplexity-researcher-1" (full ID)
 16в†’  agent_type?: string;              // "perplexity-researcher" (base type)
 17в†’  instance_number?: number;         // 1 (sequence number)
 18в†’  parent_session_id?: string;       // Session that spawned this agent
 19в†’  parent_task_id?: string;          // Task ID that spawned this agent
 20в†’}
 21в†’
 22в†’/**
 23в†’ * Extract agent instance ID from Task tool input
 24в†’ *
 25в†’ * Looks for patterns in priority order:
 26в†’ * 1. [agent-type-N] in description (e.g., "Research topic [perplexity-researcher-1]")
 27в†’ * 2. [AGENT_INSTANCE: agent-type-N] in prompt
 28в†’ * 3. subagent_type field (fallback to just type, no instance number)
 29в†’ *
 30в†’ * @param toolInput The tool input object from PreToolUse/PostToolUse hooks
 31в†’ * @param description Optional description field from tool input
 32в†’ * @returns Metadata object with extracted information
 33в†’ */
 34в†’export function extractAgentInstanceId(
 35в†’  toolInput: any,
 36в†’  description?: string
 37в†’): AgentInstanceMetadata {
 38в†’  const result: AgentInstanceMetadata = {};
 39в†’
 40в†’  // Strategy 1: Extract from description [agent-type-N]
 41в†’  // Example: "Research consumer complaints [perplexity-researcher-1]"
 42в†’  if (description) {
 43в†’    const descMatch = description.match(/\[([a-z-]+-researcher)-(\d+)\]/);
 44в†’    if (descMatch) {
 45в†’      result.agent_type = descMatch[1];
 46в†’      result.instance_number = parseInt(descMatch[2], 10);
 47в†’      result.agent_instance_id = `${result.agent_type}-${result.instance_number}`;
 48в†’    }
 49в†’  }
 50в†’
 51в†’  // Strategy 2: Extract from prompt [AGENT_INSTANCE: ...]
 52в†’  // Example: "[AGENT_INSTANCE: perplexity-researcher-1]"
 53в†’  if (!result.agent_instance_id && toolInput?.prompt && typeof toolInput.prompt === 'string') {
 54в†’    const promptMatch = toolInput.prompt.match(/\[AGENT_INSTANCE:\s*([^\]]+)\]/);
 55в†’    if (promptMatch) {
 56в†’      result.agent_instance_id = promptMatch[1].trim();
 57в†’
 58в†’      // Parse agent type and instance number from ID
 59в†’      const parts = result.agent_instance_id.match(/^([a-z-]+)-(\d+)$/);
 60в†’      if (parts) {
 61в†’        result.agent_type = parts[1];
 62в†’        result.instance_number = parseInt(parts[2], 10);
 63в†’      }
 64в†’    }
 65в†’  }
 66в†’
 67в†’  // Strategy 3: Extract parent session from prompt
 68в†’  // Example: "[PARENT_SESSION: b7062b5a-03d3-4168-9555-a748e0b2efa3]"
 69в†’  if (toolInput?.prompt && typeof toolInput.prompt === 'string') {
 70в†’    const parentSessionMatch = toolInput.prompt.match(/\[PARENT_SESSION:\s*([^\]]+)\]/);
 71в†’    if (parentSessionMatch) {
 72в†’      result.parent_session_id = parentSessionMatch[1].trim();
 73в†’    }
 74в†’
 75в†’    // Extract parent task from prompt
 76в†’    // Example: "[PARENT_TASK: research_1731445892345]"
 77в†’    const parentTaskMatch = toolInput.prompt.match(/\[PARENT_TASK:\s*([^\]]+)\]/);
 78в†’    if (parentTaskMatch) {
 79в†’      result.parent_task_id = parentTaskMatch[1].trim();
 80в†’    }
 81в†’  }
 82в†’
 83в†’  // Strategy 4: Fallback to subagent_type if available (no instance number)
 84в†’  // This ensures we at least capture the agent type even without instance IDs
 85в†’  if (!result.agent_type && toolInput?.subagent_type) {
 86в†’    result.agent_type = toolInput.subagent_type;
 87в†’  }
 88в†’
 89в†’  return result;
 90в†’}
 91в†’
 92в†’/**
 93в†’ * Enrich event with agent metadata
 94в†’ *
 95в†’ * Takes a base event object and adds agent instance metadata to it.
 96в†’ * Returns a new object with merged metadata.
 97в†’ *
 98в†’ * @param event Base event object (from PreToolUse/PostToolUse)
 99в†’ * @param toolInput Tool input object
100в†’ * @param description Optional description field
101в†’ * @returns Enriched event with agent metadata
102в†’ */
103в†’export function enrichEventWithAgentMetadata(
104в†’  event: any,
105в†’  toolInput: any,
106в†’  description?: string
107в†’): any {
108в†’  const metadata = extractAgentInstanceId(toolInput, description);
109в†’
110в†’  // Only add fields that have values (keep events clean)
111в†’  const enrichedEvent = { ...event };
112в†’
113в†’  if (metadata.agent_instance_id) {
114в†’    enrichedEvent.agent_instance_id = metadata.agent_instance_id;
115в†’  }
116в†’
117в†’  if (metadata.agent_type) {
118в†’    enrichedEvent.agent_type = metadata.agent_type;
119в†’  }
120в†’
121в†’  if (metadata.instance_number !== undefined) {
122в†’    enrichedEvent.instance_number = metadata.instance_number;
123в†’  }
124в†’
125в†’  if (metadata.parent_session_id) {
126в†’    enrichedEvent.parent_session_id = metadata.parent_session_id;
127в†’  }
128в†’
129в†’  if (metadata.parent_task_id) {
130в†’    enrichedEvent.parent_task_id = metadata.parent_task_id;
131в†’  }
132в†’
133в†’  return enrichedEvent;
134в†’}
135в†’
136в†’/**
137в†’ * Check if a tool call is spawning a subagent
138в†’ *
139в†’ * @param toolName Name of the tool being called
140в†’ * @param toolInput Tool input object
141в†’ * @returns true if this is a Task tool call spawning an agent
142в†’ */
143в†’export function isAgentSpawningCall(toolName: string, toolInput: any): boolean {
144в†’  return toolName === 'Task' && toolInput?.subagent_type !== undefined;
145в†’}
146в†’

  1в†’/**
  2в†’ * Notification Service вЂ” ntfy + voice only
  3в†’ *
  4в†’ * Simplified from multi-channel (Discord, Twilio, Desktop) to just ntfy push.
  5в†’ * Voice notifications are handled by the voice server (localhost:8888).
  6в†’ *
  7в†’ * Design principles:
  8в†’ * - Async, non-blocking (fire-and-forget)
  9в†’ * - Fail gracefully (never block hook execution)
 10в†’ * - Expandable later if needed
 11в†’ */
 12в†’
 13в†’import { readFileSync, writeFileSync, existsSync } from 'fs';
 14в†’import { join } from 'path';
 15в†’import { homedir } from 'os';
 16в†’import { getIdentity } from './identity';
 17в†’
 18в†’// ============================================================================
 19в†’// Types
 20в†’// ============================================================================
 21в†’
 22в†’export type NotificationPriority = 'min' | 'low' | 'default' | 'high' | 'urgent';
 23в†’
 24в†’export type NotificationEvent =
 25в†’  | 'taskComplete'
 26в†’  | 'longTask'
 27в†’  | 'backgroundAgent'
 28в†’  | 'error'
 29в†’  | 'security';
 30в†’
 31в†’export interface NotificationOptions {
 32в†’  title?: string;
 33в†’  priority?: NotificationPriority;
 34в†’  tags?: string[];
 35в†’  click?: string;
 36в†’  actions?: Array<{
 37в†’    action: 'view' | 'http';
 38в†’    label: string;
 39в†’    url: string;
 40в†’  }>;
 41в†’}
 42в†’
 43в†’export interface NotificationConfig {
 44в†’  ntfy: {
 45в†’    enabled: boolean;
 46в†’    topic: string;
 47в†’    server: string;
 48в†’  };
 49в†’  thresholds: {
 50в†’    longTaskMinutes: number;
 51в†’  };
 52в†’  routing: {
 53в†’    [key in NotificationEvent]: ('ntfy')[];
 54в†’  };
 55в†’}
 56в†’
 57в†’// ============================================================================
 58в†’// Configuration
 59в†’// ============================================================================
 60в†’
 61в†’const DEFAULT_CONFIG: NotificationConfig = {
 62в†’  ntfy: {
 63в†’    enabled: false,
 64в†’    topic: '',
 65в†’    server: 'ntfy.sh'
 66в†’  },
 67в†’  thresholds: {
 68в†’    longTaskMinutes: 5
 69в†’  },
 70в†’  routing: {
 71в†’    taskComplete: [],
 72в†’    longTask: ['ntfy'],
 73в†’    backgroundAgent: ['ntfy'],
 74в†’    error: ['ntfy'],
 75в†’    security: ['ntfy']
 76в†’  }
 77в†’};
 78в†’
 79в†’function expandEnvVars(content: string): string {
 80в†’  return content.replace(/\$\{(\w+)\}/g, (_, key) => process.env[key] || '');
 81в†’}
 82в†’
 83в†’export function getNotificationConfig(): NotificationConfig {
 84в†’  try {
 85в†’    const paiDir = process.env.PAI_DIR || join(homedir(), '.claude');
 86в†’    const settingsPath = join(paiDir, 'settings.json');
 87в†’
 88в†’    if (existsSync(settingsPath)) {
 89в†’      const rawContent = readFileSync(settingsPath, 'utf-8');
 90в†’      const expandedContent = expandEnvVars(rawContent);
 91в†’      const settings = JSON.parse(expandedContent);
 92в†’      if (settings.notifications) {
 93в†’        return {
 94в†’          ...DEFAULT_CONFIG,
 95в†’          ntfy: { ...DEFAULT_CONFIG.ntfy, ...settings.notifications?.ntfy },
 96в†’          thresholds: { ...DEFAULT_CONFIG.thresholds, ...settings.notifications?.thresholds },
 97в†’          routing: { ...DEFAULT_CONFIG.routing, ...settings.notifications?.routing }
 98в†’        };
 99в†’      }
100в†’    }
101в†’  } catch (error) {
102в†’    console.error('Failed to load notification config:', error);
103в†’  }
104в†’
105в†’  return DEFAULT_CONFIG;
106в†’}
107в†’
108в†’// ============================================================================
109в†’// Session Timing
110в†’// ============================================================================
111в†’
112в†’const SESSION_START_FILE = '/tmp/pai-session-start.txt';
113в†’
114в†’export function recordSessionStart(): void {
115в†’  try { writeFileSync(SESSION_START_FILE, Date.now().toString()); } catch {}
116в†’}
117в†’
118в†’export function getSessionDurationMinutes(): number {
119в†’  try {
120в†’    if (existsSync(SESSION_START_FILE)) {
121в†’      const startTime = parseInt(readFileSync(SESSION_START_FILE, 'utf-8'));
122в†’      return (Date.now() - startTime) / 1000 / 60;
123в†’    }
124в†’  } catch {}
125в†’  return 0;
126в†’}
127в†’
128в†’export function isLongRunningTask(): boolean {
129в†’  const config = getNotificationConfig();
130в†’  return getSessionDurationMinutes() >= config.thresholds.longTaskMinutes;
131в†’}
132в†’
133в†’// ============================================================================
134в†’// ntfy Push
135в†’// ============================================================================
136в†’
137в†’export async function sendPush(
138в†’  message: string,
139в†’  options: NotificationOptions = {}
140в†’): Promise<boolean> {
141в†’  const config = getNotificationConfig();
142в†’
143в†’  if (!config.ntfy.enabled || !config.ntfy.topic) {
144в†’    return false;
145в†’  }
146в†’
147в†’  try {
148в†’    const url = `https://${config.ntfy.server}/${config.ntfy.topic}`;
149в†’
150в†’    const headers: Record<string, string> = {
151в†’      'Content-Type': 'text/plain',
152в†’    };
153в†’
154в†’    if (options.title) headers['Title'] = options.title;
155в†’
156в†’    if (options.priority) {
157в†’      const priorityMap: Record<NotificationPriority, string> = {
158в†’        'min': '1', 'low': '2', 'default': '3', 'high': '4', 'urgent': '5'
159в†’      };
160в†’      headers['Priority'] = priorityMap[options.priority] || '3';
161в†’    }
162в†’
163в†’    if (options.tags?.length) headers['Tags'] = options.tags.join(',');
164в†’    if (options.click) headers['Click'] = options.click;
165в†’
166в†’    if (options.actions?.length) {
167в†’      headers['Actions'] = options.actions
168в†’        .map(a => `${a.action}, ${a.label}, ${a.url}`)
169в†’        .join('; ');
170в†’    }
171в†’
172в†’    const response = await fetch(url, {
173в†’      method: 'POST',
174в†’      headers,
175в†’      body: message,
176в†’      signal: AbortSignal.timeout(5000),
177в†’    });
178в†’
179в†’    return response.ok;
180в†’  } catch (error) {
181в†’    console.error('ntfy send failed:', error);
182в†’    return false;
183в†’  }
184в†’}
185в†’
186в†’// ============================================================================
187в†’// Smart Router
188в†’// ============================================================================
189в†’
190в†’export async function notify(
191в†’  event: NotificationEvent,
192в†’  message: string,
193в†’  options: NotificationOptions = {}
194в†’): Promise<void> {
195в†’  const config = getNotificationConfig();
196в†’  const channels = config.routing[event] || [];
197в†’
198в†’  for (const channel of channels) {
199в†’    if (channel === 'ntfy') {
200в†’      sendPush(message, {
201в†’        title: options.title || getDefaultTitle(event),
202в†’        priority: options.priority || getDefaultPriority(event),
203в†’        tags: options.tags || getDefaultTags(event),
204в†’        ...options
205в†’      }).catch(() => {});
206в†’    }
207в†’  }
208в†’}
209в†’
210в†’export async function notifyTaskComplete(message: string, options: NotificationOptions = {}): Promise<void> {
211в†’  const event: NotificationEvent = isLongRunningTask() ? 'longTask' : 'taskComplete';
212в†’  await notify(event, message, options);
213в†’}
214в†’
215в†’export async function notifyBackgroundAgent(
216в†’  agentType: string,
217в†’  message: string,
218в†’  options: NotificationOptions = {}
219в†’): Promise<void> {
220в†’  await notify('backgroundAgent', message, {
221в†’    title: `${agentType} Agent Complete`,
222в†’    tags: ['robot', 'white_check_mark'],
223в†’    ...options
224в†’  });
225в†’}
226в†’
227в†’export async function notifyError(message: string, options: NotificationOptions = {}): Promise<void> {
228в†’  await notify('error', message, {
229в†’    priority: 'high',
230в†’    tags: ['warning', 'x'],
231в†’    ...options
232в†’  });
233в†’}
234в†’
235в†’// ============================================================================
236в†’// Helpers
237в†’// ============================================================================
238в†’
239в†’function getDefaultTitle(event: NotificationEvent): string {
240в†’  const DA_NAME = getIdentity().name;
241в†’  const titles: Record<NotificationEvent, string> = {
242в†’    taskComplete: DA_NAME,
243в†’    longTask: `${DA_NAME} - Task Complete`,
244в†’    backgroundAgent: `${DA_NAME} - Agent Complete`,
245в†’    error: `${DA_NAME} - Error`,
246в†’    security: `${DA_NAME} - Security Alert`
247в†’  };
248в†’  return titles[event];
249в†’}
250в†’
251в†’function getDefaultPriority(event: NotificationEvent): NotificationPriority {
252в†’  const priorities: Record<NotificationEvent, NotificationPriority> = {
253в†’    taskComplete: 'default',
254в†’    longTask: 'default',
255в†’    backgroundAgent: 'default',
256в†’    error: 'high',
257в†’    security: 'urgent'
258в†’  };
259в†’  return priorities[event];
260в†’}
261в†’
262в†’function getDefaultTags(event: NotificationEvent): string[] {
263в†’  const tags: Record<NotificationEvent, string[]> = {
