  1в†’/**
  2в†’ * output-validators.ts - Validation for voice and tab title outputs
  3в†’ *
  4в†’ * Single source of truth for what constitutes valid/invalid output
  5в†’ * in the voice and tab title systems. NOT related to Algorithm format.
  6в†’ *
  7в†’ * Tab title validators enforce the state machine:
  8в†’ *   - Working titles (вљ™пёЏ): gerund start ("Fixing auth bug.")
  9в†’ *   - Completion titles (вњ“): past tense, NO gerund ("Fixed auth bug.")
 10в†’ *   - Question titles: noun phrase, no period ("Auth method")
 11в†’ *
 12в†’ * Renamed from response-format.ts (v0.2.32) вЂ” old name was misleading.
 13в†’ */
 14в†’
 15в†’// Conversational filler вЂ” always invalid for voice output
 16в†’const GARBAGE_PATTERNS = [
 17в†’  /appreciate/i,
 18в†’  /thank/i,
 19в†’  /welcome/i,
 20в†’  /help(ing)? you/i,
 21в†’  /assist(ing)? you/i,
 22в†’  /reaching out/i,
 23в†’  /happy to/i,
 24в†’  /let me know/i,
 25в†’  /feel free/i,
 26в†’];
 27в†’
 28в†’// Conversational starters вЂ” not factual summaries
 29в†’const CONVERSATIONAL_STARTERS = [
 30в†’  /^I'm /i, /^I am /i, /^Sure[,.]?/i, /^OK[,.]?/i,
 31в†’  /^Got it[,.]?/i, /^Done\.?$/i, /^Yes[,.]?/i, /^No[,.]?/i,
 32в†’  /^Okay[,.]?/i, /^Alright[,.]?/i,
 33в†’];
 34в†’
 35в†’// Single-word garbage
 36в†’const SINGLE_WORD_BLOCKLIST = new Set([
 37в†’  'ready', 'done', 'ok', 'okay', 'yes', 'no', 'sure',
 38в†’  'hello', 'hi', 'hey', 'thanks', 'working', 'processing',
 39в†’]);
 40в†’
 41в†’/**
 42в†’ * Check if a voice completion is valid for TTS.
 43в†’ */
 44в†’export function isValidVoiceCompletion(text: string): boolean {
 45в†’  if (!text || text.length < 10) return false;
 46в†’  const wordCount = text.trim().split(/\s+/).length;
 47в†’  if (wordCount === 1) {
 48в†’    const lower = text.toLowerCase().replace(/[^a-z]/g, '');
 49в†’    if (SINGLE_WORD_BLOCKLIST.has(lower) || lower.length < 10) return false;
 50в†’  }
 51в†’  for (const p of GARBAGE_PATTERNS) if (p.test(text)) return false;
 52в†’  if (text.length < 40) {
 53в†’    if (/\bready\b/i.test(text) || /\bhello\b/i.test(text)) return false;
 54в†’  }
 55в†’  for (const p of CONVERSATIONAL_STARTERS) if (p.test(text)) return false;
 56в†’  return true;
 57в†’}
 58в†’
 59в†’export function getVoiceFallback(): string {
 60в†’  return '';
 61в†’}
 62в†’
 63в†’// в”Ђв”Ђв”Ђ Tab Title Validation в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
 64в†’
 65в†’// Incomplete endings вЂ” dangling articles, prepositions, conjunctions
 66в†’const INCOMPLETE_ENDINGS = new Set([
 67в†’  'the', 'a', 'an', 'to', 'for', 'with', 'of',
 68в†’  'in', 'on', 'at', 'by', 'from', 'into', 'about',
 69в†’  'and', 'or', 'but', 'that', 'which',
 70в†’]);
 71в†’
 72в†’/**
 73в†’ * Shared base validation: 2-4 words, period, no garbage, no incomplete endings.
 74в†’ */
 75в†’function isValidTitleBase(text: string): { valid: boolean; firstWord: string } {
 76в†’  if (!text || text.length < 5) return { valid: false, firstWord: '' };
 77в†’  if (!text.endsWith('.')) return { valid: false, firstWord: '' };
 78в†’
 79в†’  const content = text.slice(0, -1).trim();
 80в†’  const words = content.split(/\s+/);
 81в†’  if (words.length < 2 || words.length > 4) return { valid: false, firstWord: '' };
 82в†’
 83в†’  const firstWord = words[0].toLowerCase();
 84в†’
 85в†’  // Reject generic garbage (both gerund and past-tense forms)
 86в†’  if (/^(completed?|proces{1,2}e?d|processing|handled|handling|finished|finishing|worked|working|done) (the |on )?(task|request|work|it)$/i.test(content)) {
 87в†’    return { valid: false, firstWord };
 88в†’  }
 89в†’
 90в†’  // Reject first-person pronouns
 91в†’  const lower = content.toLowerCase();
 92в†’  if (/\bi\b/.test(lower) || /\bme\b/.test(lower) || /\bmy\b/.test(lower)) {
 93в†’    return { valid: false, firstWord };
 94в†’  }
 95в†’
 96в†’  // Reject dangling/incomplete endings
 97в†’  const lastWord = words[words.length - 1].toLowerCase().replace(/[^a-z]/g, '');
 98в†’  if (INCOMPLETE_ENDINGS.has(lastWord)) return { valid: false, firstWord };
 99в†’
100в†’  return { valid: true, firstWord };
101в†’}
102в†’
103в†’/**
104в†’ * Working-phase title: MUST start with gerund (-ing verb).
105в†’ * Used by UpdateTabTitle for рџ§ /вљ™пёЏ titles.
106в†’ */
107в†’export function isValidWorkingTitle(text: string): boolean {
108в†’  const { valid, firstWord } = isValidTitleBase(text);
109в†’  if (!valid) return false;
110в†’  return firstWord.endsWith('ing');
111в†’}
112в†’
113в†’/** @deprecated Use isValidWorkingTitle */
114в†’export const isValidTabSummary = isValidWorkingTitle;
115в†’
116в†’/**
117в†’ * Completion-phase title: must NOT start with gerund.
118в†’ * Past tense or other non-gerund verb forms.
119в†’ * Used by TabState for вњ“ titles.
120в†’ */
121в†’export function isValidCompletionTitle(text: string): boolean {
122в†’  const { valid, firstWord } = isValidTitleBase(text);
123в†’  if (!valid) return false;
124в†’  // Completion titles must NOT be gerunds вЂ” that's a working title
125в†’  if (firstWord.endsWith('ing')) return false;
126в†’  return true;
127в†’}
128в†’
129в†’/**
130в†’ * Question-phase title: noun phrase, no period, 1-4 words, max 30 chars.
131в†’ */
132в†’export function isValidQuestionTitle(text: string): boolean {
133в†’  if (!text || text.trim().length === 0) return false;
134в†’  if (text.endsWith('.')) return false;
135в†’  if (text.length > 30) return false;
136в†’  const words = text.trim().split(/\s+/);
137в†’  if (words.length < 1 || words.length > 4) return false;
138в†’  if (/<[^>]*>/.test(text)) return false;
139в†’  return true;
140в†’}
141в†’
142в†’// в”Ђв”Ђв”Ђ Fallbacks в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
143в†’
144в†’export function getWorkingFallback(): string {
145в†’  return 'Processing request.';
146в†’}
147в†’
148в†’export function getCompletionFallback(): string {
149в†’  return 'Task complete.';
150в†’}
151в†’
152в†’export function getQuestionFallback(): string {
153в†’  return 'Awaiting input';
154в†’}
155в†’
156в†’/** @deprecated Use getWorkingFallback or getCompletionFallback */
157в†’export function getTabFallback(stage: 'start' | 'end' = 'start'): string {
158в†’  return stage === 'end' ? getCompletionFallback() : getWorkingFallback();
159в†’}
160в†’
161в†’// в”Ђв”Ђв”Ђ Past Tense Conversion в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
162в†’
163в†’const IRREGULAR_PAST: Record<string, string> = {
164в†’  building: 'Built', running: 'Ran', writing: 'Wrote', reading: 'Read',
165в†’  making: 'Made', finding: 'Found', getting: 'Got', setting: 'Set',
166в†’  doing: 'Did', going: 'Went', taking: 'Took', giving: 'Gave',
167в†’  seeing: 'Saw', sending: 'Sent', thinking: 'Thought', bringing: 'Brought',
168в†’  beginning: 'Began', breaking: 'Broke', choosing: 'Chose', drawing: 'Drew',
169в†’  driving: 'Drove', eating: 'Ate', falling: 'Fell', flying: 'Flew',
170в†’  growing: 'Grew', hiding: 'Hid', holding: 'Held', keeping: 'Kept',
171в†’  knowing: 'Knew', leading: 'Led', leaving: 'Left', lending: 'Lent',
172в†’  letting: 'Let', losing: 'Lost', meeting: 'Met', paying: 'Paid',
173в†’  putting: 'Put', riding: 'Rode', rising: 'Rose', saying: 'Said',
174в†’  selling: 'Sold', showing: 'Showed', singing: 'Sang', sitting: 'Sat',
175в†’  sleeping: 'Slept', speaking: 'Spoke', spending: 'Spent', standing: 'Stood',
176в†’  stealing: 'Stole', striking: 'Struck', sweeping: 'Swept', swimming: 'Swam',
177в†’  teaching: 'Taught', telling: 'Told', throwing: 'Threw', wearing: 'Wore',
178в†’  winning: 'Won', understanding: 'Understood',
179в†’};
