181в†’/**
182в†’ * Convert a gerund to past tense: "Fixing" в†’ "Fixed", "Building" в†’ "Built".
183в†’ */
184в†’export function gerundToPastTense(gerund: string): string {
185в†’  const lower = gerund.toLowerCase();
186в†’
187в†’  // Check irregular map first
188в†’  if (IRREGULAR_PAST[lower]) return IRREGULAR_PAST[lower];
189в†’
190в†’  if (!lower.endsWith('ing') || lower.length < 5) return gerund;
191в†’  const stem = lower.slice(0, -3);
192в†’
193в†’  // Regular: stem + "ed" handles all cases correctly:
194в†’  // - "fixing" в†’ stem "fix" в†’ "fixed"
195в†’  // - "stopping" в†’ stem "stopp" в†’ "stopped" (doubled consonant preserved)
196в†’  // - "processing" в†’ stem "process" в†’ "processed" (natural 'ss' preserved)
197в†’  const result = stem + 'ed';
198в†’  return result.charAt(0).toUpperCase() + result.slice(1);
199в†’}
