 1в†’/**
 2в†’ * Centralized Path Resolution
 3в†’ *
 4в†’ * Handles environment variable expansion for portable PAI configuration.
 5в†’ * Claude Code doesn't expand $HOME in settings.json env values, so we do it here.
 6в†’ *
 7в†’ * Usage:
 8в†’ *   import { getPaiDir, getSettingsPath } from './lib/paths';
 9в†’ *   const paiDir = getPaiDir(); // Always returns expanded absolute path
10в†’ */
11в†’
12в†’import { homedir } from 'os';
13в†’import { join } from 'path';
14в†’
15в†’/**
16в†’ * Expand shell variables in a path string
17в†’ * Supports: $HOME, ${HOME}, ~
18в†’ */
19в†’export function expandPath(path: string): string {
20в†’  const home = homedir();
21в†’
22в†’  return path
23в†’    .replace(/^\$HOME(?=\/|$)/, home)
24в†’    .replace(/^\$\{HOME\}(?=\/|$)/, home)
25в†’    .replace(/^~(?=\/|$)/, home);
26в†’}
27в†’
28в†’/**
29в†’ * Get the PAI directory (expanded)
30в†’ * Priority: PAI_DIR env var (expanded) в†’ ~/.claude
31в†’ */
32в†’export function getPaiDir(): string {
33в†’  const envPaiDir = process.env.PAI_DIR;
34в†’
35в†’  if (envPaiDir) {
36в†’    return expandPath(envPaiDir);
37в†’  }
38в†’
39в†’  return join(homedir(), '.claude');
40в†’}
41в†’
42в†’/**
43в†’ * Get the settings.json path
44в†’ */
45в†’export function getSettingsPath(): string {
46в†’  return join(getPaiDir(), 'settings.json');
47в†’}
48в†’
49в†’/**
50в†’ * Get a path relative to PAI_DIR
51в†’ */
52в†’export function paiPath(...segments: string[]): string {
53в†’  return join(getPaiDir(), ...segments);
54в†’}
55в†’
56в†’/**
57в†’ * Get the hooks directory
58в†’ */
59в†’export function getHooksDir(): string {
