 18в†’/**
 19в†’ * Generate a PRD filename: PRD-{YYYYMMDD}-{slug}.md
 20в†’ */
 21в†’export function generatePRDFilename(slug: string): string {
 22в†’  const now = new Date();
 23в†’  const y = now.getFullYear();
 24в†’  const m = String(now.getMonth() + 1).padStart(2, "0");
 25в†’  const d = String(now.getDate()).padStart(2, "0");
 26в†’  return `PRD-${y}${m}${d}-${slug}.md`;
 27в†’}
 28в†’
 29в†’/**
 30в†’ * Generate a PRD ID: PRD-{YYYYMMDD}-{slug}
 31в†’ */
 32в†’export function generatePRDId(slug: string): string {
 33в†’  const now = new Date();
 34в†’  const y = now.getFullYear();
 35в†’  const m = String(now.getMonth() + 1).padStart(2, "0");
 36в†’  const d = String(now.getDate()).padStart(2, "0");
 37в†’  return `PRD-${y}${m}${d}-${slug}`;
