 40в†’/**
 41в†’ * Generate a complete PRD file with frontmatter and sections.
 42в†’ * Frontmatter fields match algorithm.ts readPRD() parser exactly.
 43в†’ */
 44в†’export function generatePRDTemplate(opts: PRDOptions): string {
 45в†’  const today = new Date().toISOString().split("T")[0];
 46в†’  const id = generatePRDId(opts.slug);
 47в†’  const effort = opts.effortLevel || "Standard";
 48в†’  const mode = opts.mode || "interactive";
 49в†’  const promptSection = opts.prompt
 50в†’    ? `### Problem Space\n${opts.prompt.substring(0, 500)}\n`
 51в†’    : `### Problem Space\n_To be populated during OBSERVE phase._\n`;
 52в†’
 53в†’  return `---
 54в†’prd: true
 55в†’id: ${id}
 56в†’status: DRAFT
 57в†’mode: ${mode}
 58в†’effort_level: ${effort}
 59в†’created: ${today}
 60в†’updated: ${today}
 61в†’iteration: 0
