  1в†’/**
  2в†’ * tab-setter.ts - Unified tab state setter.
  3в†’ *
  4в†’ * Single function that:
  5в†’ * 1. Sets Kitty tab title and color via remote control
  6в†’ * 2. Persists per-window state for daemon recovery
  7в†’ *
  8в†’ * All hooks call setTabState() instead of directly running kitten commands.
  9в†’ */
 10в†’
 11в†’import { existsSync, writeFileSync, mkdirSync, readdirSync, unlinkSync, readFileSync } from 'fs';
 12в†’import { join } from 'path';
 13в†’import { execSync } from 'child_process';
 14в†’import { TAB_COLORS, PHASE_TAB_CONFIG, ACTIVE_TAB_BG, ACTIVE_TAB_FG, INACTIVE_TAB_FG, type TabState, type AlgorithmTabPhase } from './tab-constants';
 15в†’import { paiPath } from './paths';
 16в†’
 17в†’const TAB_TITLES_DIR = paiPath('MEMORY', 'STATE', 'tab-titles');
 18в†’const KITTY_SESSIONS_DIR = paiPath('MEMORY', 'STATE', 'kitty-sessions');
 19в†’
 20в†’/**
 21в†’ * Get Kitty environment from env vars or persisted per-session file.
 22в†’ *
 23в†’ * Resolution order:
 24в†’ * 1. Process env vars (direct terminal context вЂ” always correct)
 25в†’ * 2. Per-session file: kitty-sessions/{sessionId}.json (no shared state, no races)
 26в†’ */
 27в†’function getKittyEnv(sessionId?: string): { listenOn: string | null; windowId: string | null } {
 28в†’  // Try environment first (direct terminal calls)
 29в†’  let listenOn = process.env.KITTY_LISTEN_ON || null;
 30в†’  let windowId = process.env.KITTY_WINDOW_ID || null;
 31в†’  if (listenOn && windowId) return { listenOn, windowId };
 32в†’
 33в†’  // Per-session file lookup (preferred вЂ” no shared mutable state)
 34в†’  if (sessionId) {
 35в†’    try {
 36в†’      const sessionPath = join(KITTY_SESSIONS_DIR, `${sessionId}.json`);
 37в†’      if (existsSync(sessionPath)) {
 38в†’        const entry = JSON.parse(readFileSync(sessionPath, 'utf-8'));
 39в†’        listenOn = listenOn || entry.listenOn || null;
 40в†’        windowId = windowId || entry.windowId || null;
 41в†’        if (listenOn && windowId) return { listenOn, windowId };
 42в†’      }
 43в†’    } catch { /* silent */ }
 44в†’  }
 45в†’
 46в†’  // Log when kitty env lookup fails with a session ID (diagnostic for compaction issues)
 47в†’  if (sessionId && !listenOn && !windowId) {
 48в†’    console.error(`[tab-setter] getKittyEnv: no kitty env found for session ${sessionId.slice(0, 8)} (no env vars, no session file)`);
 49в†’  }
 50в†’
 51в†’  return { listenOn, windowId };
 52в†’}
 53в†’
 54в†’/**
 55в†’ * Persist a session's Kitty environment for later hook lookups.
 56в†’ * Called by StartupGreeting at session start.
 57в†’ *
 58в†’ * Each session gets its own file: kitty-sessions/{sessionId}.json
 59в†’ * - No shared mutable state (concurrent session starts are safe)
 60в†’ * - No unbounded growth (files cleaned up on session end)
 61в†’ * - Simple atomic write (no read-modify-write cycle)
 62в†’ *
 63в†’ */
 64в†’export function persistKittySession(sessionId: string, listenOn: string, windowId: string): void {
 65в†’  try {
 66в†’    if (!existsSync(KITTY_SESSIONS_DIR)) mkdirSync(KITTY_SESSIONS_DIR, { recursive: true });
 67в†’    writeFileSync(
 68в†’      join(KITTY_SESSIONS_DIR, `${sessionId}.json`),
 69в†’      JSON.stringify({ listenOn, windowId }),
 70в†’      'utf-8'
 71в†’    );
 72в†’  } catch { /* silent */ }
 73в†’}
 74в†’
 75в†’/**
 76в†’ * Remove a session's persisted Kitty environment file.
 77в†’ * Called by SessionSummary at session end.
 78в†’ */
 79в†’export function cleanupKittySession(sessionId: string): void {
 80в†’  try {
 81в†’    const sessionPath = join(KITTY_SESSIONS_DIR, `${sessionId}.json`);
 82в†’    if (existsSync(sessionPath)) unlinkSync(sessionPath);
 83в†’  } catch { /* silent */ }
 84в†’}
 85в†’
 86в†’interface SetTabOptions {
 87в†’  title: string;
 88в†’  state: TabState;
 89в†’  previousTitle?: string;
 90в†’  sessionId?: string;
 91в†’}
 92в†’
 93в†’/**
 94в†’ * Clean up state files for kitty windows that no longer exist.
 95в†’ * Runs opportunistically on each setTabState call (lightweight).
 96в†’ */
 97в†’function cleanupStaleStateFiles(): void {
 98в†’  try {
 99в†’    if (!existsSync(TAB_TITLES_DIR)) return;
100в†’    const files = readdirSync(TAB_TITLES_DIR).filter(f => f.endsWith('.json'));
101в†’    if (files.length === 0) return;
102в†’
103в†’    // Get live window IDs from kitty
104в†’    const liveOutput = execSync('kitten @ ls 2>/dev/null | jq -r ".[].tabs[].windows[].id" 2>/dev/null', {
105в†’      encoding: 'utf-8', timeout: 2000,
106в†’    }).trim();
107в†’    if (!liveOutput) return;
108в†’
109в†’    const liveIds = new Set(liveOutput.split('\n').map(id => id.trim()));
110в†’
111в†’    for (const file of files) {
112в†’      const winId = file.replace('.json', '');
113в†’      if (!liveIds.has(winId)) {
114в†’        try { unlinkSync(join(TAB_TITLES_DIR, file)); } catch { /* silent */ }
115в†’      }
116в†’    }
117в†’  } catch { /* silent вЂ” cleanup is best-effort */ }
118в†’}
119в†’
120в†’export function setTabState(opts: SetTabOptions): void {
121в†’  const { title, state, previousTitle, sessionId } = opts;
122в†’  const colors = TAB_COLORS[state];
123в†’  const kittyEnv = getKittyEnv(sessionId);
124в†’
125в†’  try {
126в†’    // Need either TERM=xterm-kitty OR a valid KITTY_LISTEN_ON to proceed
127в†’    const isKitty = process.env.TERM === 'xterm-kitty' || kittyEnv.listenOn;
128в†’    if (!isKitty) return;
129в†’
130в†’    const escaped = title.replace(/"/g, '\\"');
131в†’    // Set BOTH tab title AND window title. Kitty's tab_title_template uses
132в†’    // {active_window.title} (the window title). OSC escape codes from Claude Code
133в†’    // reset set-tab-title overrides, so the template falls back to window title.
134в†’    // By setting both, our title survives OSC resets.
135в†’    //
136в†’    // Use --to flag with KITTY_LISTEN_ON for remote control when not in terminal context
137в†’    const toFlag = kittyEnv.listenOn ? `--to="${kittyEnv.listenOn}"` : '';
138в†’    console.error(`[tab-setter] Setting tab: "${escaped}" with toFlag: ${toFlag || '(none)'}`);
139в†’    execSync(`kitten @ ${toFlag} set-tab-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
140в†’    execSync(`kitten @ ${toFlag} set-window-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
141в†’
142в†’    // For idle state, reset ALL colors to Kitty defaults (no lingering backgrounds)
143в†’    if (state === 'idle') {
144в†’      execSync(
145в†’        `kitten @ ${toFlag} set-tab-color --self active_bg=none active_fg=none inactive_bg=none inactive_fg=none`,
146в†’        { stdio: 'ignore', timeout: 2000 }
147в†’      );
148в†’    } else {
149в†’      execSync(
150в†’        `kitten @ ${toFlag} set-tab-color --self active_bg=${ACTIVE_TAB_BG} active_fg=${ACTIVE_TAB_FG} inactive_bg=${colors.inactiveBg} inactive_fg=${INACTIVE_TAB_FG}`,
151в†’        { stdio: 'ignore', timeout: 2000 }
152в†’      );
153в†’    }
154в†’    console.error(`[tab-setter] Tab commands completed successfully`);
155в†’  } catch (err) {
156в†’    console.error(`[tab-setter] Error setting tab:`, err);
157в†’  }
158в†’
159в†’  // Persist per-window state (or clean up on idle/session end)
160в†’  const windowId = kittyEnv.windowId;
161в†’  if (!windowId) return;
162в†’
163в†’  try {
164в†’    if (state === 'idle') {
165в†’      // Session ended вЂ” remove state file so no stale data lingers
166в†’      const statePath = join(TAB_TITLES_DIR, `${windowId}.json`);
167в†’      if (existsSync(statePath)) unlinkSync(statePath);
168в†’    } else {
169в†’      if (!existsSync(TAB_TITLES_DIR)) mkdirSync(TAB_TITLES_DIR, { recursive: true });
170в†’      const stateData: Record<string, unknown> = {
171в†’        title,
172в†’        inactiveBg: colors.inactiveBg,
173в†’        state,
174в†’        timestamp: new Date().toISOString(),
175в†’      };
176в†’      if (previousTitle) stateData.previousTitle = previousTitle;
177в†’      writeFileSync(join(TAB_TITLES_DIR, `${windowId}.json`), JSON.stringify(stateData), 'utf-8');
178в†’    }
179в†’  } catch { /* silent */ }
180в†’
181в†’  // Opportunistic cleanup of stale state files for dead windows
182в†’  cleanupStaleStateFiles();
183в†’}
184в†’
185в†’/**
186в†’ * Read per-window state file. Returns null if not found or invalid.
187в†’ */
188в†’export function readTabState(sessionId?: string): { title: string; state: TabState; previousTitle?: string; phase?: string } | null {
189в†’  const kittyEnv = getKittyEnv(sessionId);
190в†’  const windowId = kittyEnv.windowId;
191в†’  if (!windowId) return null;
192в†’  try {
193в†’    const statePath = join(TAB_TITLES_DIR, `${windowId}.json`);
194в†’    if (!existsSync(statePath)) return null;
195в†’    const raw = JSON.parse(require('fs').readFileSync(statePath, 'utf-8'));
196в†’    return {
197в†’      title: raw.title || '',
198в†’      state: raw.state || 'idle',
199в†’      previousTitle: raw.previousTitle,
200в†’      phase: raw.phase,
201в†’    };
202в†’  } catch { return null; }
203в†’}
204в†’
205в†’/**
206в†’ * Strip emoji prefix from a tab title to get raw text.
207в†’ * Handles both working-state prefixes (рџ§ вљ™пёЏвњ“вќ“) and Algorithm phase symbols (рџ‘ЃпёЏрџ“‹рџ”ЁвљЎвњ…рџ“љ).
208в†’ */
209в†’export function stripPrefix(title: string): string {
210в†’  return title.replace(/^(?:рџ§ |вљ™пёЏ|вљ™|вњ“|вќ“|рџ‘ЃпёЏ|рџ“‹|рџ”Ё|вљЎ|вњ…|рџ“љ)\s*/, '').trim();
211в†’}
212в†’
213в†’// Noise words to skip when extracting the session label
214в†’const SESSION_NOISE = new Set([
215в†’  'the', 'a', 'an', 'and', 'or', 'for', 'to', 'in', 'on', 'of', 'with',
216в†’  'my', 'our', 'new', 'old', 'fix', 'add', 'update', 'set', 'get',
217в†’]);
218в†’
219в†’/**
220в†’ * Extract two representative words from a session name.
221в†’ * "Tab Title Upgrade" в†’ "TAB TITLE", "Security Redesign" в†’ "SECURITY REDESIGN"
222в†’ * "Fix Activity Dashboard" в†’ "ACTIVITY DASHBOARD"
223в†’ * Returns uppercase. Falls back to first two words if all are noise.
224в†’ */
225в†’export function getSessionOneWord(sessionId: string): string | null {
226в†’  try {
227в†’    const namesPath = paiPath('MEMORY', 'STATE', 'session-names.json');
228в†’    if (!existsSync(namesPath)) return null;
229в†’    const names = JSON.parse(readFileSync(namesPath, 'utf-8'));
230в†’    const fullName = names[sessionId];
231в†’    if (!fullName) return null;
232в†’
233в†’    const words = fullName.split(/\s+/).filter((w: string) => w.length > 0);
234в†’    if (words.length === 0) return null;
235в†’
236в†’    // Collect up to 2 non-noise words
237в†’    const meaningful = words.filter((w: string) => !SESSION_NOISE.has(w.toLowerCase()));
238в†’    if (meaningful.length >= 2) {
239в†’      return `${meaningful[0]} ${meaningful[1]}`.toUpperCase();
240в†’    } else if (meaningful.length === 1) {
241в†’      // One meaningful word вЂ” grab the next word (even if noise) for context
242в†’      const idx = words.indexOf(meaningful[0]);
243в†’      const next = words[idx + 1];
244в†’      if (next) return `${meaningful[0]} ${next}`.toUpperCase();
245в†’      return meaningful[0].toUpperCase();
246в†’    }
247в†’    // All noise вЂ” take first two
248в†’    return words.slice(0, 2).join(' ').toUpperCase();
249в†’  } catch {
250в†’    return null;
251в†’  }
252в†’}
253в†’
254в†’/**
255в†’ * Set tab title and color for an Algorithm phase.
256в†’ * Active format:    {SYMBOL} {ONE_WORD} | {PHASE}
257в†’ * Complete format:  {ONE_WORD} | {summary}
258в†’ *
259в†’ * Called by AlgorithmTracker on phase transitions.
260в†’ */
261в†’export function setPhaseTab(phase: AlgorithmTabPhase, sessionId: string, summary?: string): void {
262в†’  const config = PHASE_TAB_CONFIG[phase];
263в†’  if (!config) return;
264в†’
265в†’  const oneWord = getSessionOneWord(sessionId) || 'WORKING';
266в†’  const kittyEnv = getKittyEnv(sessionId);
267в†’
268в†’  // Build title based on phase
269в†’  let title: string;
270в†’  if (phase === 'COMPLETE' && summary) {
271в†’    title = `вњ… ${summary}`;
272в†’  } else if (phase === 'COMPLETE') {
273в†’    // No summary extracted вЂ” use session name instead of generic "Done."
274в†’    title = `вњ… ${oneWord}`;
275в†’  } else if (phase === 'IDLE') {
276в†’    title = oneWord;
277в†’  } else {
278в†’    // Preserve existing working description from UpdateTabTitle if available.
279в†’    // Only swap the emoji prefix to show current phase вЂ” keep the real task context.
280в†’    let existingDesc = '';
281в†’    const currentState = readTabState(sessionId);
282в†’    if (currentState?.title) {
283в†’      const pipeIdx = currentState.title.indexOf('|');
284в†’      if (pipeIdx !== -1) existingDesc = currentState.title.slice(pipeIdx + 1).trim();
285в†’    }
286в†’    const desc = existingDesc || config.gerund;
287в†’    title = `${config.symbol} ${oneWord} | ${desc}`;
288в†’  }
289в†’
290в†’  try {
291в†’    const isKitty = process.env.TERM === 'xterm-kitty' || kittyEnv.listenOn;
292в†’    if (!isKitty) return;
293в†’
294в†’    const escaped = title.replace(/"/g, '\\"');
295в†’    const toFlag = kittyEnv.listenOn ? `--to="${kittyEnv.listenOn}"` : '';
296в†’
297в†’    execSync(`kitten @ ${toFlag} set-tab-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
298в†’    execSync(`kitten @ ${toFlag} set-window-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
299в†’
300в†’    if (phase === 'IDLE') {
