  1в†’/**
  2в†’ * Shared Time Utilities
  3в†’ *
  4в†’ * Consistent timestamp generation across the hook system.
  5в†’ * Reads timezone from settings.json via principal.timezone
  6в†’ * Used by: All hooks that need timestamps
  7в†’ */
  8в†’
  9в†’import { getPrincipal } from './identity';
 10в†’
 11в†’/**
 12в†’ * Get configured timezone from settings.json (defaults to UTC)
 13в†’ */
 14в†’function getTimezone(): string {
 15в†’  return getPrincipal().timezone || 'UTC';
 16в†’}
 17в†’
 18в†’/**
 19в†’ * Get full timestamp string: "YYYY-MM-DD HH:MM:SS TZ"
 20в†’ */
 21в†’export function getPSTTimestamp(): string {
 22в†’  const timezone = getTimezone();
 23в†’  const date = new Date();
 24в†’  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
 25в†’
 26в†’  const year = localDate.getFullYear();
 27в†’  const month = String(localDate.getMonth() + 1).padStart(2, '0');
 28в†’  const day = String(localDate.getDate()).padStart(2, '0');
 29в†’  const hours = String(localDate.getHours()).padStart(2, '0');
 30в†’  const minutes = String(localDate.getMinutes()).padStart(2, '0');
 31в†’  const seconds = String(localDate.getSeconds()).padStart(2, '0');
 32в†’
 33в†’  // Get short timezone name
 34в†’  const tzName = date.toLocaleString('en-US', { timeZone: timezone, timeZoneName: 'short' }).split(' ').pop() || 'UTC';
 35в†’
 36в†’  return `${year}-${month}-${day} ${hours}:${minutes}:${seconds} ${tzName}`;
 37в†’}
 38в†’
 39в†’/**
 40в†’ * Get date only: "YYYY-MM-DD"
 41в†’ */
 42в†’export function getPSTDate(): string {
 43в†’  const timezone = getTimezone();
 44в†’  const date = new Date();
 45в†’  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
 46в†’
 47в†’  const year = localDate.getFullYear();
 48в†’  const month = String(localDate.getMonth() + 1).padStart(2, '0');
 49в†’  const day = String(localDate.getDate()).padStart(2, '0');
 50в†’
 51в†’  return `${year}-${month}-${day}`;
 52в†’}
 53в†’
 54в†’/**
 55в†’ * Get year-month for directory structure: "YYYY-MM"
 56в†’ */
 57в†’export function getYearMonth(): string {
 58в†’  return getPSTDate().substring(0, 7);
 59в†’}
 60в†’
 61в†’/**
 62в†’ * Get ISO8601 timestamp with timezone offset
 63в†’ */
 64в†’export function getISOTimestamp(): string {
 65в†’  const timezone = getTimezone();
 66в†’  const date = new Date();
 67в†’  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
 68в†’
 69в†’  const year = localDate.getFullYear();
 70в†’  const month = String(localDate.getMonth() + 1).padStart(2, '0');
 71в†’  const day = String(localDate.getDate()).padStart(2, '0');
 72в†’  const hours = String(localDate.getHours()).padStart(2, '0');
 73в†’  const minutes = String(localDate.getMinutes()).padStart(2, '0');
 74в†’  const seconds = String(localDate.getSeconds()).padStart(2, '0');
 75в†’
 76в†’  // Calculate offset from UTC
 77в†’  const utcDate = new Date(date.toLocaleString('en-US', { timeZone: 'UTC' }));
 78в†’  const diffMs = localDate.getTime() - utcDate.getTime();
 79в†’  const diffHours = Math.floor(Math.abs(diffMs) / (1000 * 60 * 60));
 80в†’  const diffMins = Math.floor((Math.abs(diffMs) % (1000 * 60 * 60)) / (1000 * 60));
 81в†’  const sign = diffMs >= 0 ? '+' : '-';
 82в†’  const offset = `${sign}${String(diffHours).padStart(2, '0')}:${String(diffMins).padStart(2, '0')}`;
 83в†’
 84в†’  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
 85в†’}
 86в†’
 87в†’/**
 88в†’ * Get timestamp formatted for filenames: "YYYY-MM-DD-HHMMSS"
 89в†’ */
 90в†’export function getFilenameTimestamp(): string {
 91в†’  const timezone = getTimezone();
 92в†’  const date = new Date();
 93в†’  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
 94в†’
 95в†’  const year = localDate.getFullYear();
 96в†’  const month = String(localDate.getMonth() + 1).padStart(2, '0');
 97в†’  const day = String(localDate.getDate()).padStart(2, '0');
 98в†’  const hours = String(localDate.getHours()).padStart(2, '0');
 99в†’  const minutes = String(localDate.getMinutes()).padStart(2, '0');
100в†’  const seconds = String(localDate.getSeconds()).padStart(2, '0');
101в†’
102в†’  return `${year}-${month}-${day}-${hours}${minutes}${seconds}`;
103в†’}
104в†’
105в†’/**
106в†’ * Get timestamp components for custom formatting
107в†’ */
108в†’export function getPSTComponents(): {
109в†’  year: number;
110в†’  month: string;
111в†’  day: string;
112в†’  hours: string;
113в†’  minutes: string;
114в†’  seconds: string;
115в†’} {
116в†’  const timezone = getTimezone();
117в†’  const date = new Date();
118в†’  const localDate = new Date(date.toLocaleString('en-US', { timeZone: timezone }));
119в†’
120в†’  return {
121в†’    year: localDate.getFullYear(),
122в†’    month: String(localDate.getMonth() + 1).padStart(2, '0'),
123в†’    day: String(localDate.getDate()).padStart(2, '0'),
124в†’    hours: String(localDate.getHours()).padStart(2, '0'),
125в†’    minutes: String(localDate.getMinutes()).padStart(2, '0'),
126в†’    seconds: String(localDate.getSeconds()).padStart(2, '0'),
127в†’  };
128в†’}
129в†’
130в†’/**
131в†’ * Get timezone string for display
132в†’ */
133в†’export function getTimezoneDisplay(): string {
134в†’  const timezone = getTimezone();
135в†’  const date = new Date();
136в†’  return date.toLocaleString('en-US', { timeZone: timezone, timeZoneName: 'short' }).split(' ').pop() || timezone;
137в†’}
