  1в†’/**
  2в†’ * ResponseCapture.ts - Response Capture Handler
  3в†’ *
  4в†’ * PURPOSE:
  5в†’ * Captures completed responses and updates task status.
  6в†’ * Also handles learning capture for significant insights and sends notifications.
  7в†’ * Extracts and persists ISC (Ideal State Criteria) to current task's ISC.json.
  8в†’ *
  9в†’ * STRUCTURE:
 10в†’ * Session: WORK/{session_dir}/
 11в†’ * Task: WORK/{session_dir}/tasks/{current_task}/
 12в†’ *   - ISC.json (task's criteria)
 13в†’ *   - THREAD.md (task's algorithm log with frontmatter metadata)
 14в†’ */
 15в†’
 16в†’import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
 17в†’import { join } from 'path';
 18в†’import { getPaiDir } from '../lib/paths';
 19в†’import { sendEventToObservability, getCurrentTimestamp, getSourceApp } from '../lib/observability';
 20в†’import { notifyTaskComplete, notifyError, getSessionDurationMinutes } from '../lib/notifications';
 21в†’import { getLearningCategory, isLearningCapture } from '../lib/learning-utils';
 22в†’import { getPSTTimestamp, getPSTDate, getYearMonth, getISOTimestamp } from '../lib/time';
 23в†’import type { ParsedTranscript, StructuredResponse } from '../../skills/PAI/Tools/TranscriptParser';
 24в†’
 25в†’const BASE_DIR = getPaiDir();
 26в†’const WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
 27в†’const STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
 28в†’const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
 29в†’
 30в†’// ============================================================================
 31в†’// Types
 32в†’// ============================================================================
 33в†’
 34в†’interface CurrentWork {
 35в†’  session_id: string;
 36в†’  session_dir: string;
 37в†’  current_task: string;
 38в†’  task_count: number;
 39в†’  created_at: string;
 40в†’}
 41в†’
 42в†’interface HookInput {
 43в†’  session_id: string;
 44в†’  transcript_path: string;
 45в†’  hook_event_name: string;
 46в†’}
 47в†’
 48в†’type EffortLevel = 'QUICK' | 'STANDARD' | 'THOROUGH' | 'TRIVIAL';
 49в†’
 50в†’interface ISCDocument {
 51в†’  taskId: string;
 52в†’  status: string;
 53в†’  effortLevel: string;
 54в†’  criteria: string[];
 55в†’  antiCriteria: string[];
 56в†’  satisfaction: {
 57в†’    satisfied: number;
 58в†’    partial: number;
 59в†’    failed: number;
 60в†’    total: number;
 61в†’  } | null;
 62в†’  createdAt: string;
 63в†’  updatedAt: string;
 64в†’}
 65в†’
 66в†’// ============================================================================
 67в†’// ISC Extraction Helpers
 68в†’// ============================================================================
 69в†’
 70в†’function extractEffortLevel(text: string): EffortLevel | null {
 71в†’  const match = text.match(/level\s+(QUICK|STANDARD|THOROUGH|TRIVIAL)/i);
 72в†’  return match ? (match[1].toUpperCase() as EffortLevel) : null;
 73в†’}
 74в†’
 75в†’function extractISCSatisfaction(text: string): ISCDocument['satisfaction'] | null {
 76в†’  // Match patterns like "6 ISC criteria, all satisfied"
 77в†’  const allSatisfied = text.match(/(\d+)\s*(?:ISC\s*)?criteria?,?\s*all\s*satisfied/i);
 78в†’  if (allSatisfied) {
 79в†’    const total = parseInt(allSatisfied[1], 10);
 80в†’    return { satisfied: total, partial: 0, failed: 0, total };
 81в†’  }
 82в†’
 83в†’  // Match: X/Y criteria satisfied
 84в†’  const partial = text.match(/(\d+)\/(\d+)\s*criteria\s*satisfied/i);
 85в†’  if (partial) {
 86в†’    return {
 87в†’      satisfied: parseInt(partial[1], 10),
 88в†’      total: parseInt(partial[2], 10),
 89в†’      partial: 0,
 90в†’      failed: 0,
 91в†’    };
 92в†’  }
 93в†’
 94в†’  return null;
 95в†’}
 96в†’
 97в†’// ============================================================================
 98в†’// Task ISC Update
 99в†’// ============================================================================
100в†’
101в†’/**
102в†’ * Update task's ISC.json with extracted satisfaction data
103в†’ */
104в†’function updateTaskISC(sessionDir: string, currentTask: string, text: string): void {
105в†’  const taskPath = join(WORK_DIR, sessionDir, 'tasks', currentTask);
106в†’  const iscPath = join(taskPath, 'ISC.json');
107в†’
108в†’  if (!existsSync(iscPath)) {
109в†’    console.error(`[ISC] Task ISC.json not found: ${iscPath}`);
110в†’    return;
111в†’  }
112в†’
113в†’  try {
114в†’    const doc: ISCDocument = JSON.parse(readFileSync(iscPath, 'utf-8'));
115в†’    const timestamp = getISOTimestamp();
116в†’
117в†’    // Extract effort level if found
118в†’    const effort = extractEffortLevel(text);
119в†’    if (effort) {
120в†’      doc.effortLevel = effort;
121в†’    }
122в†’
123в†’    // Extract satisfaction from response
124в†’    const satisfaction = extractISCSatisfaction(text);
125в†’    if (satisfaction) {
126в†’      doc.satisfaction = satisfaction;
127в†’      doc.status = satisfaction.satisfied === satisfaction.total ? 'COMPLETE' : 'PARTIAL';
128в†’    }
129в†’
130в†’    // Check for completion marker
131в†’    if (text.includes('вњ“ COMPLETE')) {
132в†’      doc.status = 'COMPLETE';
133в†’    }
134в†’
135в†’    doc.updatedAt = timestamp;
136в†’
137в†’    writeFileSync(iscPath, JSON.stringify(doc, null, 2), 'utf-8');
138в†’    console.error(`[ISC] Updated task ISC: ${currentTask}`);
139в†’  } catch (err) {
140в†’    console.error(`[ISC] Error updating task ISC: ${err}`);
141в†’  }
142в†’}
143в†’
144в†’/**
145в†’ * Update task THREAD.md frontmatter status
146в†’ */
147в†’function updateTaskMeta(sessionDir: string, currentTask: string, structured: StructuredResponse): void {
148в†’  const taskPath = join(WORK_DIR, sessionDir, 'tasks', currentTask);
149в†’  const threadPath = join(taskPath, 'THREAD.md');
150в†’
151в†’  if (!existsSync(threadPath)) {
152в†’    console.error(`[Capture] Task THREAD.md not found: ${threadPath}`);
153в†’    return;
154в†’  }
155в†’
156в†’  try {
157в†’    let content = readFileSync(threadPath, 'utf-8');
158в†’    const timestamp = getISOTimestamp();
159в†’
160в†’    // Update status if complete
161в†’    if (structured.completed || structured.summary) {
162в†’      content = content.replace(/^status: "IN_PROGRESS"$/m, 'status: "DONE"');
163в†’
164в†’      // Add completedAt if not present in frontmatter
165в†’      if (!content.includes('completedAt:')) {
166в†’        content = content.replace(/^(---\n[\s\S]*?)(---)/, `$1completedAt: "${timestamp}"\n$2`);
167в†’      }
168в†’
169в†’      // Add summary if not present in frontmatter
170в†’      const summary = (structured.completed || structured.summary || '').substring(0, 200);
171в†’      if (summary && !content.includes('summary:')) {
172в†’        content = content.replace(/^(---\n[\s\S]*?)(---)/, `$1summary: "${summary.replace(/"/g, '\\"')}"\n$2`);
173в†’      }
174в†’    }
175в†’
176в†’    writeFileSync(threadPath, content, 'utf-8');
177в†’    console.error(`[Capture] Updated task THREAD: ${currentTask}`);
178в†’  } catch (err) {
179в†’    console.error(`[Capture] Error updating task META: ${err}`);
180в†’  }
181в†’}
182в†’
183в†’// ============================================================================
184в†’// Learning Capture
185в†’// ============================================================================
186в†’
187в†’function generateFilename(description: string, type: 'LEARNING' | 'WORK'): string {
188в†’  const pstTimestamp = getPSTTimestamp();
189в†’  const date = pstTimestamp.slice(0, 10);
190в†’  const time = pstTimestamp.slice(11, 19).replace(/:/g, '');
191в†’
192в†’  const cleanDesc = description
193в†’    .toLowerCase()
194в†’    .replace(/[^a-z0-9\s-]/g, '')
195в†’    .replace(/\s+/g, '-')
196в†’    .slice(0, 60);
197в†’
198в†’  return `${date}-${time}_${type}_${cleanDesc}.md`;
199в†’}
200в†’
201в†’function generateLearningContent(structured: StructuredResponse, fullText: string, timestamp: string): string {
202в†’  return `---
203в†’capture_type: LEARNING
204в†’timestamp: ${timestamp}
205в†’auto_captured: true
206в†’tags: [auto-capture]
207в†’---
208в†’
209в†’# Quick Learning: ${structured.completed || structured.summary || 'Task Completion'}
210в†’
211в†’**Date:** ${structured.date || getPSTDate()}
212в†’**Auto-captured:** Yes
213в†’
214в†’---
215в†’
216в†’## Summary
217в†’
218в†’${structured.summary || 'N/A'}
219в†’
220в†’## Analysis
221в†’
222в†’${structured.analysis || 'N/A'}
223в†’
224в†’## Actions Taken
225в†’
226в†’${structured.actions || 'N/A'}
227в†’
228в†’## Results
229в†’
230в†’${structured.results || 'N/A'}
231в†’
232в†’## Current Status
233в†’
234в†’${structured.status || 'N/A'}
235в†’
236в†’## Next Steps
237в†’
238в†’${structured.next || 'N/A'}
239в†’
240в†’---
241в†’
242в†’<details>
243в†’<summary>Full Response</summary>
244в†’
245в†’${fullText.replace(/<system-reminder>[\s\S]*?<\/system-reminder>/g, '')}
246в†’
247в†’</details>
248в†’`;
249в†’}
250в†’
251в†’// ============================================================================
252в†’// Main Capture Logic
253в†’// ============================================================================
254в†’
255в†’function readCurrentWork(): CurrentWork | null {
256в†’  try {
257в†’    if (!existsSync(CURRENT_WORK_FILE)) return null;
258в†’    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
259в†’  } catch {
260в†’    return null;
261в†’  }
262в†’}
